export enum Occasion {
  Birthday = 'Birthday',
  Eid = 'Eid',
  Valentine = 'Valentine',
  NewYear = 'New Year',
  Anniversary = 'Anniversary'
}

export interface WishData {
  recipientName: string;
  occasion: Occasion;
  relationship?: string;
}

export interface GeneratedWish {
  message: string;
  mood: string;
  colorTheme: string;
  recipientName: string;
  occasion: Occasion;
}

export interface ThemeConfig {
  gradient: string;
  particleType: 'heart' | 'confetti' | 'star' | 'crescent' | 'sparkle';
  primaryColor: string;
}

import { Occasion, ThemeConfig } from '../types';

export const OCCASION_THEMES: Record<Occasion, ThemeConfig> = {
  [Occasion.Birthday]: {
    gradient: 'from-amber-400 via-orange-500 to-yellow-600',
    particleType: 'confetti',
    primaryColor: '#f59e0b'
  },
  [Occasion.Eid]: {
    gradient: 'from-emerald-600 via-teal-700 to-cyan-800',
    particleType: 'crescent',
    primaryColor: '#059669'
  },
  [Occasion.Valentine]: {
    gradient: 'from-rose-500 via-pink-600 to-purple-600',
    particleType: 'heart',
    primaryColor: '#e11d48'
  },
  [Occasion.NewYear]: {
    gradient: 'from-blue-600 via-indigo-700 to-slate-900',
    particleType: 'sparkle',
    primaryColor: '#2563eb'
  },
  [Occasion.Anniversary]: {
    gradient: 'from-purple-600 via-fuchsia-600 to-pink-500',
    particleType: 'star',
    primaryColor: '#9333ea'
  }
};

import { GoogleGenAI, Type } from "@google/genai";
import { WishData, GeneratedWish } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateWish = async (data: WishData): Promise<GeneratedWish> => {
  const prompt = `Generate a personalized, warm, and heartfelt card message for ${data.recipientName} on the occasion of ${data.occasion}. 
  The relationship is "${data.relationship || 'Friend'}". 
  Keep the message short (max 20 words). 
  Return a JSON object with a message, mood, and colorTheme (Tailwind gradient class).`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          message: { type: Type.STRING, description: 'The personalized wish text' },
          mood: { type: Type.STRING, description: 'Single word vibe like festive, cozy, romantic' },
          colorTheme: { type: Type.STRING, description: 'A suggested tailwind bg-gradient class' }
        },
        required: ['message', 'mood', 'colorTheme']
      }
    }
  });

  const result = JSON.parse(response.text);

  return {
    ...result,
    recipientName: data.recipientName,
    occasion: data.occasion
  };
};

import React, { useState } from 'react';
import { Occasion, WishData } from '../types';
import { Sparkles, Send } from 'lucide-react';

interface WishFormProps {
  onSubmit: (data: WishData) => void;
  isLoading: boolean;
}

const WishForm: React.FC<WishFormProps> = ({ onSubmit, isLoading }) => {
  const [formData, setFormData] = useState<WishData>({
    recipientName: '',
    occasion: Occasion.Birthday,
    relationship: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.recipientName) return;
    onSubmit(formData);
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6 bg-slate-800/50 backdrop-blur-md p-8 rounded-2xl border border-slate-700 shadow-xl">
      <div className="space-y-2">
        <label className="text-sm font-medium text-slate-300 block">Recipient Name</label>
        <input
          type="text"
          value={formData.recipientName}
          onChange={(e) => setFormData({ ...formData, recipientName: e.target.value })}
          placeholder="Who is this for?"
          className="w-full bg-slate-900/50 border border-slate-700 rounded-lg px-4 py-3 text-white focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all outline-none"
          required
        />
      </div>

      <div className="space-y-2">
        <label className="text-sm font-medium text-slate-300 block">The Occasion</label>
        <select
          value={formData.occasion}
          onChange={(e) => setFormData({ ...formData, occasion: e.target.value as Occasion })}
          className="w-full bg-slate-900/50 border border-slate-700 rounded-lg px-4 py-3 text-white focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all outline-none appearance-none"
        >
          {Object.values(Occasion).map((occ) => (
            <option key={occ} value={occ}>{occ}</option>
          ))}
        </select>
      </div>

      <div className="space-y-2">
        <label className="text-sm font-medium text-slate-300 block">Relationship (Optional)</label>
        <input
          type="text"
          value={formData.relationship}
          onChange={(e) => setFormData({ ...formData, relationship: e.target.value })}
          placeholder="e.g. Brother, Best Friend, Partner"
          className="w-full bg-slate-900/50 border border-slate-700 rounded-lg px-4 py-3 text-white focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all outline-none"
        />
      </div>

      <button
        type="submit"
        disabled={isLoading || !formData.recipientName}
        className={`w-full py-4 px-6 rounded-xl font-bold text-white flex items-center justify-center gap-2 transition-all shadow-lg ${
          isLoading 
          ? 'bg-slate-700 cursor-not-allowed' 
          : 'bg-gradient-to-r from-indigo-600 to-violet-600 hover:from-indigo-500 hover:to-violet-500 hover:scale-[1.02] active:scale-[0.98]'
        }`}
