        ) : (
          <>
            <Sparkles className="w-5 h-5" />
            Generate Wish
          </>
        )}
      </button>
    </form>
  );
};

export default WishForm;

import React, { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { GeneratedWish } from '../types';
import { OCCASION_THEMES } from '../lib/themes';
import { Heart, Star, Moon, Sparkles, Gift } from 'lucide-react';

interface WishCardProps {
  wish: GeneratedWish | null;
  isLoading: boolean;
}

const Particle: React.FC<{ type: string; color: string }> = ({ type, color }) => {
  const [randoms] = useState(() => ({
    x: Math.random() * 100,
    size: 10 + Math.random() * 20,
    duration: 3 + Math.random() * 5,
    delay: Math.random() * 5,
    rotate: Math.random() * 360
  }));

  const renderIcon = () => {
    switch (type) {
      case 'heart': return <Heart fill={color} stroke="none" className="opacity-40" />;
      case 'star': return <Star fill={color} stroke="none" className="opacity-40" />;
      case 'crescent': return <Moon fill={color} stroke="none" className="opacity-40" />;
      case 'sparkle': return <Sparkles fill={color} stroke="none" className="opacity-40" />;
      default: return <div className="rounded-full w-2 h-2" style={{ backgroundColor: color }} />;
    }
  };

  return (
    <motion.div
      initial={{ y: '110%', x: `${randoms.x}%`, opacity: 0, scale: 0 }}
      animate={{ 
        y: '-10%', 
        opacity: [0, 0.4, 0.4, 0],
        rotate: randoms.rotate + 360,
        scale: 1
      }}
      transition={{ 
        duration: randoms.duration, 
        repeat: Infinity, 
        delay: randoms.delay,
        ease: "linear"
      }}
      className="absolute pointer-events-none"
      style={{ width: randoms.size, height: randoms.size }}
    >
      {renderIcon()}
    </motion.div>
  );
};

const WishCard: React.FC<WishCardProps> = ({ wish, isLoading }) => {
  const [displayedMessage, setDisplayedMessage] = useState('');

  useEffect(() => {
    if (wish?.message) {
      setDisplayedMessage('');
      let i = 0;
      const interval = setInterval(() => {
        setDisplayedMessage(wish.message.slice(0, i));
        i++;
        if (i > wish.message.length) clearInterval(interval);
      }, 40);
      return () => clearInterval(interval);
    }
  }, [wish?.message]);

  if (isLoading) {
    return (
      <div className="w-full aspect-[4/5] md:aspect-[3/4] rounded-3xl overflow-hidden bg-slate-800 flex flex-col items-center justify-center p-8 border border-slate-700 shadow-2xl relative">
        <div className="w-16 h-16 border-4 border-indigo-500/20 border-t-indigo-500 rounded-full animate-spin mb-4" />
        <p className="text-slate-400 font-medium animate-pulse">Personalizing your magic card...</p>
      </div>
    );
  }

  if (!wish) {
    return (
      <div className="w-full aspect-[4/5] md:aspect-[3/4] rounded-3xl overflow-hidden border-2 border-dashed border-slate-700 bg-slate-900/20 flex flex-col items-center justify-center p-12 text-center group">
        <div className="w-20 h-20 rounded-full bg-slate-800 flex items-center justify-center mb-6 transition-transform group-hover:scale-110 duration-500">
          <Gift className="w-10 h-10 text-slate-500" />
        </div>
        <h3 className="text-xl font-semibold text-slate-400 mb-2">Ready to create?</h3>
        <p className="text-slate-500">Fill in the form to generate a beautiful AI wish card.</p>
      </div>
    );
  }

  const theme = OCCASION_THEMES[wish.occasion];

  return (
    <AnimatePresence mode="wait">
      <motion.div
        key={wish.message}
        initial={{ opacity: 0, y: 20, scale: 0.95 }}
        animate={{ opacity: 1, y: 0, scale: 1 }}
        exit={{ opacity: 0, scale: 1.05 }}
        className="w-full aspect-[4/5] md:aspect-[3/4] rounded-3xl overflow-hidden relative shadow-2xl shadow-indigo-500/10 border border-white/10 group"
      >
        {/* Animated Background */}
        <div className={`absolute inset-0 bg-gradient-to-br ${theme.gradient} opacity-90 transition-all duration-700`} />

        {/* Glassmorphism Overlays */}
        <div className="absolute inset-0 bg-white/5 backdrop-blur-[2px]" />
        <div className="absolute top-0 inset-x-0 h-40 bg-gradient-to-b from-black/20 to-transparent" />
        <div className="absolute bottom-0 inset-x-0 h-40 bg-gradient-to-t from-black/20 to-transparent" />

        {/* Particles */}
        <div className="absolute inset-0 overflow-hidden pointer-events-none">
          {[...Array(20)].map((_, i) => (
            <Particle key={i} type={theme.particleType} color="white" />
          ))}
        </div>

        {/* Card Content */}
        <div className="absolute inset-0 flex flex-col items-center justify-center p-8 md:p-12 text-center z-10">
          <motion.div
            initial={{ opacity: 0, scale: 0.8 }}
            animate={{ opacity: 1, scale: 1 }}
            transition={{ delay: 0.3 }}
            className="mb-8"
          >
            <div className="w-20 h-20 rounded-full bg-white/10 backdrop-blur-md flex items-center justify-center mx-auto mb-4 border border-white/20 shadow-lg">
              {theme.particleType === 'heart' && <Heart className="w-10 h-10 text-white fill-white" />}
              {theme.particleType === 'confetti' && <Gift className="w-10 h-10 text-white" />}
              {theme.particleType === 'crescent' && <Moon className="w-10 h-10 text-white fill-white" />}
              {theme.particleType === 'star' && <Star className="w-10 h-10 text-white fill-white" />}
              {theme.particleType === 'sparkle' && <Sparkles className="w-10 h-10 text-white" />}
            </div>
            <span className="inline-block px-4 py-1.5 rounded-full bg-black/20 backdrop-blur-md text-xs font-bold tracking-widest uppercase text-white/80 border border-white/10">
              {wish.occasion}
            </span>
          </motion.div>

          <motion.h2 
            className="text-4xl md:text-5xl lg:text-6xl font-serif text-white mb-6 drop-shadow-lg"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.5 }}
          >
            Dear {wish.recipientName},
          </motion.h2>

          <div className="min-h-[100px] flex items-center justify-center">
            <p className="text-xl md:text-2xl text-white/90 leading-relaxed font-medium drop-shadow-md">
              {displayedMessage}
              <motion.span
                animate={{ opacity: [1, 0] }}
                transition={{ duration: 0.8, repeat: Infinity }}
                className="inline-block w-1 h-7 bg-white ml-1 align-middle"
              />
            </p>
          </div>

          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 1.5 }}
            className="mt-12 pt-8 border-t border-white/10 w-full"
          >
            <p className="text-white/60 text-sm font-medium tracking-wide">
              Meticulously Crafted for You
            </p>
          </motion.div>
        </div>

        {/* Subtle Outer Glow */}
        <div className="absolute inset-0 rounded-3xl border border-white/20 pointer-events-none group-hover:border-white/40 transition-colors duration-500" />
      </motion.div>
    </AnimatePresence>
  );
};

