import React, { useState } from 'react';
import WishForm from './components/WishForm';
import WishCard from './components/WishCard';
import { WishData, GeneratedWish } from './types';
import { generateWish } from './services/geminiService';
import { Sparkles, Download, Share2, Github } from 'lucide-react';

const App: React.FC = () => {
  const [wish, setWish] = useState<GeneratedWish | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = async (data: WishData) => {
    setIsLoading(true);
    setError(null);
    try {
      const result = await generateWish(data);
      setWish(result);
    } catch (err) {
      console.error(err);
      setError("Failed to brew your magic wish. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleShare = async () => {
    if (!wish) return;

    if (navigator.share) {
      const shareData: ShareData = {
        title: 'My WishCraft Card',
        text: `${wish.message}\n\n- Sent via WishCraft`,
      };

      // Check if current URL is a valid standard URL (not a blob/data URI)
      // Some sandbox environments use blob: URLs which navigator.share rejects
      const currentUrl = window.location.href;
      if (currentUrl.startsWith('http')) {
        shareData.url = currentUrl;
      }

      try {
        await navigator.share(shareData);
      } catch (err: any) {
        // If it failed specifically due to an invalid URL, try sharing without it
        if (err.name === 'TypeError' || (err.message && err.message.toLowerCase().includes('url'))) {
          try {
            await navigator.share({
              title: shareData.title,
              text: shareData.text
            });
          } catch (retryErr) {
            console.error('Final share attempt failed:', retryErr);
          }
        } else if (err.name !== 'AbortError') {
          console.error('Share failed:', err);
        }
      }
    } else {
      // Fallback: Copy to clipboard
      try {
        await navigator.clipboard.writeText(`${wish.message}\n\nSent via WishCraft`);
        alert("Wish copied to clipboard! Share it anywhere.");
      } catch (clipErr) {
        alert("Sharing not supported. You can copy the wish text manually.");
      }
    }
  };

  return (
    <div className="min-h-screen bg-[#0f172a] text-slate-100 flex flex-col">
      {/* Navbar */}
      <nav className="border-b border-slate-800 bg-slate-900/50 backdrop-blur-md sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg">
              <Sparkles className="w-6 h-6 text-white" />
            </div>
            <span className="text-xl font-bold tracking-tight">WishCraft</span>
          </div>
          <div className="flex items-center gap-4">
            <a href="https://github.com" target="_blank" rel="noopener noreferrer" className="p-2 hover:bg-slate-800 rounded-full transition-colors">
              <Github className="w-5 h-5 text-slate-400" />
            </a>
          </div>
        </div>
      </nav>

      {/* Hero / Header */}
      <header className="py-12 px-4 text-center max-w-4xl mx-auto">
        <h1 className="text-4xl md:text-6xl font-bold mb-4 bg-gradient-to-r from-white via-indigo-200 to-indigo-400 bg-clip-text text-transparent">
          Craft Magic in Every Wish
        </h1>
        <p className="text-slate-400 text-lg md:text-xl">
          Enter a few details and let our AI weaver craft a personalized, animated card for your loved ones.
        </p>
      </header>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 w-full pb-20">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 items-start">

          {/* Form Section */}
          <div className="lg:col-span-5">
            <div className="sticky top-24">
              <div className="mb-6 flex items-center gap-2 text-indigo-400 font-semibold uppercase tracking-wider text-sm">
                <div className="h-px w-8 bg-indigo-500/30" />
                Input Details
              </div>
              <WishForm onSubmit={handleGenerate} isLoading={isLoading} />

              {error && (
                <div className="mt-4 p-4 bg-rose-500/10 border border-rose-500/20 text-rose-400 rounded-xl text-sm">
                  {error}
                </div>
              )}

              <div className="mt-8 p-6 rounded-2xl bg-indigo-500/5 border border-indigo-500/10">
                <h4 className="text-white font-medium mb-2 flex items-center gap-2">
                   ✨ How it works
                </h4>
