import React, { useEffect, useState, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { GeneratedWish } from '../types';
import { OCCASION_THEMES } from '../lib/themes';
import { Heart, Star, Moon, Sparkles, Gift, Music, Download } from 'lucide-react';
import * as htmlToImage from 'html-to-image';
import gifshot from 'gifshot';

interface WishCardProps {
  wish: GeneratedWish | null;
  isLoading: boolean;
  isSharedView?: boolean;
}

const Floating3DIcon: React.FC<{ icon: string; delay: number }> = ({ icon, delay }) => {
  const [randoms] = useState(() => ({
    x: Math.random() * 100,
    y: Math.random() * 100,
    z: Math.random() * 200 - 100,
    rotateX: Math.random() * 360,
    rotateY: Math.random() * 360,
    duration: 10 + Math.random() * 10,
    scale: 0.5 + Math.random() * 1
  }));

  return (
    <motion.div
      initial={{ opacity: 0, z: -500 }}
      animate={{ 
        opacity: [0, 0.6, 0.6, 0],
        x: [`${randoms.x}%`, `${(randoms.x + 10) % 100}%`],
        y: [`${randoms.y}%`, `${(randoms.y - 15) % 100}%`],
        rotateX: [randoms.rotateX, randoms.rotateX + 360],
        rotateY: [randoms.rotateY, randoms.rotateY + 360],
        scale: [randoms.scale, randoms.scale * 1.2],
        z: [randoms.z, randoms.z + 50]
      }}
      transition={{ 
        duration: randoms.duration, 
        repeat: Infinity, 
        delay,
        ease: "linear"
      }}
      className="absolute text-4xl pointer-events-none select-none drop-shadow-2xl filter blur-[1px]"
      style={{ left: `${randoms.x}%`, top: `${randoms.y}%`, transformStyle: 'preserve-3d' }}
    >
      {icon}
    </motion.div>
  );
};

const WishCard: React.FC<WishCardProps> = ({ wish, isLoading, isSharedView }) => {
  const [displayedMessage, setDisplayedMessage] = useState('');
  const [isGifExporting, setIsGifExporting] = useState(false);
  const [exportProgress, setExportProgress] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [audioBlocked, setAudioBlocked] = useState(false);
  const cardRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    if (wish?.message) {
      setDisplayedMessage('');
      let i = 0;
      const interval = setInterval(() => {
        setDisplayedMessage(wish.message.slice(0, i));
        i++;
        if (i > wish.message.length) clearInterval(interval);
      }, 50);

      const theme = OCCASION_THEMES[wish.occasion];
      if (theme?.audioUrl) {
        const audio = new Audio(theme.audioUrl);
        audio.loop = false; // Important: Play only once
        audio.volume = 0.5;

        audio.onplay = () => {
          setIsPlaying(true);
          setAudioBlocked(false);
        };
        audio.onpause = () => setIsPlaying(false);
        audio.onended = () => setIsPlaying(false);

        audioRef.current = audio;

        // Autoplay attempt
        audio.play().catch(() => {
          setAudioBlocked(true);
          setIsPlaying(false);
        });
      }

      return () => {
        clearInterval(interval);
        if (audioRef.current) {
          audioRef.current.pause();
          audioRef.current = null;
        }
      };
    }
  }, [wish?.message, wish?.occasion]);

  const toggleAudio = () => {
    if (!audioRef.current) return;
    if (audioRef.current.paused) {
      if (audioRef.current.ended) {
        audioRef.current.currentTime = 0;
      }
      audioRef.current.play().then(() => setAudioBlocked(false));
    } else {
      audioRef.current.pause();
    }
  };

  const captureGif = async () => {
    if (!cardRef.current || !wish) return;
    setIsGifExporting(true);
    setExportProgress(0);

    const frames: string[] = [];
    const frameCount = 12; 

    try {
      const options = {
        quality: 0.95,
        filter: (node: HTMLElement) => {
          const exclusionClasses = ['gif-controls'];
          return !exclusionClasses.some(cls => node.classList?.contains(cls));
        },
        style: { transform: 'scale(1)', borderRadius: '24px' }
      };

      for (let i = 0; i < frameCount; i++) {
        const dataUrl = await htmlToImage.toPng(cardRef.current, options);
        frames.push(dataUrl);
        setExportProgress(Math.round(((i + 1) / frameCount) * 50));
        await new Promise(r => setTimeout(r, 150));
      }

      gifshot.createGIF({
        images: frames,
        gifWidth: 400,
        gifHeight: 500,
        interval: 0.15,
        numFrames: frameCount,
      }, (obj: any) => {
        if (!obj.error) {
          const link = document.createElement('a');
          link.download = `WishCraft-${wish.recipientName}-${wish.occasion}.gif`;
          link.href = obj.image;
          link.click();
        }
        setIsGifExporting(false);
        setExportProgress(100);
      });
    } catch (err) {
      console.error(err);
      setIsGifExporting(false);
    }
  };

  if (isLoading) {
    return (
      <div className="w-full aspect-[4/5] rounded-3xl bg-slate-800 flex flex-col items-center justify-center p-8 border border-slate-700 shadow-2xl">
        <div className="relative">
          <div className="w-20 h-20 border-4 border-indigo-500/20 border-t-indigo-500 rounded-full animate-spin" />
          <Sparkles className="absolute inset-0 m-auto w-8 h-8 text-indigo-400 animate-pulse" />
        </div>
        <p className="mt-6 text-slate-400 font-medium animate-pulse tracking-wide">Weaving AI Magic...</p>
      </div>
    );
  }

  if (!wish) {
    return (
      <div className="w-full aspect-[4/5] rounded-3xl border-2 border-dashed border-slate-700 bg-slate-900/20 flex flex-col items-center justify-center p-12 text-center group">
        <motion.div 
          animate={{ y: [0, -10, 0] }} 
          transition={{ duration: 3, repeat: Infinity }}
          className="w-24 h-24 rounded-full bg-slate-800 flex items-center justify-center mb-6 shadow-xl"
        >
          <Gift className="w-12 h-12 text-slate-500" />
        </motion.div>
        <h3 className="text-2xl font-bold text-slate-300 mb-2">The Canvas Awaits</h3>
        <p className="text-slate-500 max-w-xs">Fill in the details to create a 3D animated wish masterpiece.</p>
      </div>
    );
  }

  const theme = OCCASION_THEMES[wish.occasion];

  return (
    <div className="relative group perspective-1000">
      <AnimatePresence mode="wait">
        <motion.div
          ref={cardRef}
          key={wish.message}
          initial={{ opacity: 0, rotateY: -10, scale: 0.9 }}
          animate={{ opacity: 1, rotateY: 0, scale: 1 }}
          exit={{ opacity: 0, scale: 1.1 }}
          className="w-full aspect-[4/5] rounded-3xl overflow-hidden relative shadow-2xl border border-white/20 preserve-3d"
        >
          <div className={`absolute inset-0 bg-gradient-to-br ${theme.gradient} opacity-95`} />
