    const duration = 3 * 1000;
    const animationEnd = Date.now() + duration;
    const defaults = { startVelocity: 30, spread: 360, ticks: 60, zIndex: 100 };

    const randomInRange = (min: number, max: number) => Math.random() * (max - min) + min;

    const interval: any = setInterval(function() {
      const timeLeft = animationEnd - Date.now();

      if (timeLeft <= 0) {
        return clearInterval(interval);
      }

      const particleCount = 50 * (timeLeft / duration);
      confetti({ ...defaults, particleCount, origin: { x: randomInRange(0.1, 0.3), y: Math.random() - 0.2 } });
      confetti({ ...defaults, particleCount, origin: { x: randomInRange(0.7, 0.9), y: Math.random() - 0.2 } });
    }, 250);
  }, []);

  // Safe Unicode Base64 Encoding
  const encodeData = (data: any) => {
    const json = JSON.stringify(data);
    // Use encodeURIComponent to handle non-Latin1 characters before b64
    return btoa(encodeURIComponent(json).replace(/%([0-9A-F]{2})/g, (match, p1) => 
      String.fromCharCode(parseInt(p1, 16))
    ));
  };

  // Safe Unicode Base64 Decoding
  const decodeData = (str: string) => {
    try {
      const decoded = decodeURIComponent(Array.prototype.map.call(atob(str), (c) => {
        return '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2);
      }).join(''));
      return JSON.parse(decoded);
    } catch (e) {
      console.error("Decoding error:", e);
      return null;
    }
  };

  // Handle Shared Link on Mount and Hash Change
  useEffect(() => {
    const handleHash = () => {
      const hash = window.location.hash;
      if (hash && hash.startsWith('#wish=')) {
        const encodedData = hash.replace('#wish=', '');
        const decodedData = decodeData(encodedData);
        if (decodedData) {
          setWish(decodedData);
          setIsSharedView(true);
          triggerConfetti();
        }
      }
    };

    handleHash();
    window.addEventListener('hashchange', handleHash);
    return () => window.removeEventListener('hashchange', handleHash);
  }, [triggerConfetti]);

  const handleGenerate = async (data: WishData) => {
    setIsLoading(true);
    setError(null);
