    }
  };

  // Robust Unicode-safe Base64 Decoding
  const decodeData = (str: string) => {
    try {
      const binary = atob(str);
      const bytes = new Uint8Array(binary.length);
      for (let i = 0; i < binary.length; i++) {
        bytes[i] = binary.charCodeAt(i);
      }
      const json = new TextDecoder().decode(bytes);
      return JSON.parse(json);
    } catch (e) {
      console.error("Decoding error:", e);
      return null;
    }
  };

  // Handle Shared Link on Mount and Hash Change
  useEffect(() => {
    const handleHash = () => {
      const hash = window.location.hash;
      if (hash && hash.startsWith('#wish=')) {
        const encodedData = hash.replace('#wish=', '');
        const decodedData = decodeData(encodedData);
        if (decodedData) {
          setWish(decodedData);
          setIsSharedView(true);
          // Small delay to ensure the DOM is ready for the confetti canvas
          setTimeout(() => triggerConfetti(decodedData.occasion), 600);
        }
      }
    };

    handleHash();
    window.addEventListener('hashchange', handleHash);
    return () => window.removeEventListener('hashchange', handleHash);
  }, [triggerConfetti]);

  const handleGenerate = async (data: WishData) => {
    setIsLoading(true);
    setError(null);
    setIsSharedView(false);
    try {
      if (data.manualMessage && data.manualMessage.trim()) {
        const manualWish: GeneratedWish = {
          message: data.manualMessage.trim(),
          mood: 'custom',
          colorTheme: 'from-slate-800 to-slate-900', // Default, will be overridden by theme.gradient in WishCard anyway
          recipientName: data.recipientName,
          occasion: data.occasion
        };
        setWish(manualWish);
        triggerConfetti(data.occasion);
      } else {
        const result = await generateWish(data);
        setWish(result);
        triggerConfetti(result.occasion);
      }
    } catch (err) {
      console.error(err);
      setError("Failed to brew your magic wish. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const copyToClipboard = (text: string) => {
    const onCopySuccess = () => {
      setIsCopied(true);
      setTimeout(() => setIsCopied(false), 2000);
    };

    if (navigator.clipboard && window.isSecureContext) {
      navigator.clipboard.writeText(text)
        .then(onCopySuccess)
        .catch((err) => {
          console.warn("Clipboard API failed, trying fallback:", err);
          fallbackCopyTextToClipboard(text, onCopySuccess);
        });
    } else {
      fallbackCopyTextToClipboard(text, onCopySuccess);
    }
  };

  const fallbackCopyTextToClipboard = (text: string, callback?: () => void) => {
    const textArea = document.createElement("textarea");
    textArea.value = text;
    textArea.style.position = "fixed";
    textArea.style.left = "-999999px";
    textArea.style.top = "-999999px";
    document.body.appendChild(textArea);
    textArea.focus();
    textArea.select();

    try {
      const successful = document.execCommand('copy');
      if (successful && callback) callback();
      else if (!successful) prompt("Could not auto-copy. Please copy this link manually:", text);
    } catch (err) {
      console.error("Fallback copy failed:", err);
      prompt("Could not auto-copy. Please copy this link manually:", text);
    }

    document.body.removeChild(textArea);
  };

  const getShareUrl = () => {
    if (!wish) return '';
    const encodedWish = encodeData(wish);
    const baseUrl = window.location.href.split('#')[0];
    return `${baseUrl}#wish=${encodedWish}`;
  };

  const handleShare = async () => {
    const shareUrl = getShareUrl();
    if (!shareUrl) return;

    if (navigator.share) {
      try {
        await navigator.share({
          title: `Magic Wish for ${wish?.recipientName}`,
          text: `I created a special AI wish card for you! ✨`,
          url: shareUrl,
        });
      } catch (err: any) {
        if (err.name !== 'AbortError') {
          copyToClipboard(shareUrl);
        }
      }
    } else {
      copyToClipboard(shareUrl);
    }
  };

  return (
    <div className="min-h-screen bg-[#0f172a] text-slate-100 flex flex-col font-sans">
      <nav className="border-b border-white/5 bg-slate-900/60 backdrop-blur-xl sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => {
            window.location.hash = '';
            window.location.reload();
          }}>
            <div className="bg-gradient-to-br from-indigo-500 to-violet-600 p-2.5 rounded-xl shadow-lg shadow-indigo-500/20">
              <Sparkles className="w-6 h-6 text-white" />
            </div>
            <span className="text-2xl font-bold tracking-tight bg-gradient-to-r from-white to-slate-400 bg-clip-text text-transparent">
              WishCraft
            </span>
          </div>
          <div className="flex items-center gap-4">
            {isSharedView && (
              <button 
                onClick={() => { window.location.hash = ''; window.location.reload(); }}
                className="flex items-center gap-2 px-4 py-2 rounded-xl bg-indigo-600 text-sm font-bold hover:bg-indigo-500 transition-all shadow-lg shadow-indigo-500/10"
              >
                <Plus className="w-4 h-4" />
                Create Mine
              </button>
            )}
            <a href="https://github.com" target="_blank" rel="noopener noreferrer" className="p-2.5 hover:bg-white/5 rounded-xl transition-all border border-white/5">
              <Github className="w-5 h-5 text-slate-400" />
            </a>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-6 w-full pt-12 pb-24">
        {!isSharedView && !wish && (
          <header className="text-center max-w-3xl mx-auto mb-16 space-y-6">
            <h1 className="text-5xl md:text-7xl font-extrabold tracking-tight leading-tight">
              Personalized Wishes, <span className="bg-gradient-to-r from-indigo-400 to-fuchsia-400 bg-clip-text text-transparent">Perfected.</span>
            </h1>
            <p className="text-slate-400 text-lg md:text-xl font-medium leading-relaxed">
              Create cinematic, 3D animated cards with manual input or AI. 
              Share magic links with music, motion, and celebration.
            </p>
          </header>
        )}

        {isSharedView && (
           <div className="text-center mb-8 flex flex-col items-center gap-2 animate-bounce">
              <div className="p-3 bg-indigo-500/20 rounded-full text-indigo-400">
                <Volume2 className="w-6 h-6" />
              </div>
              <p className="text-indigo-400 font-bold uppercase tracking-[0.2em] text-xs">Sound On • Magic Inside</p>
           </div>
        )}

        <div className={`grid grid-cols-1 ${isSharedView ? 'lg:grid-cols-1 justify-center' : 'lg:grid-cols-12'} gap-12 items-start`}>
          {!isSharedView && (
            <div className="lg:col-span-5 space-y-8">
              <div className="bg-slate-800/30 border border-white/5 p-8 rounded-3xl backdrop-blur-md shadow-2xl">
                <div className="flex items-center gap-3 mb-8">
                  <div className="w-1.5 h-6 bg-indigo-500 rounded-full" />
                  <h3 className="text-xl font-bold">Craft Your Card</h3>
                </div>
                <WishForm onSubmit={handleGenerate} isLoading={isLoading} />
              </div>

              {error && (
                <div className="p-5 bg-rose-500/10 border border-rose-500/20 text-rose-400 rounded-2xl text-sm font-medium">
                  {error}
                </div>
              )}

              <div className="grid grid-cols-2 gap-4">
                <div className="p-6 rounded-3xl bg-white/5 border border-white/5 flex flex-col gap-3">
                  <Music className="w-6 h-6 text-indigo-400" />
                  <p className="text-xs font-bold text-slate-300 uppercase tracking-wider">Themed Audio</p>
                  <p className="text-xs text-slate-500">Fixed curated sounds for every occasion.</p>
                </div>
                <div className="p-6 rounded-3xl bg-white/5 border border-white/5 flex flex-col gap-3">
                  <Share2 className="w-6 h-6 text-fuchsia-400" />
                  <p className="text-xs font-bold text-slate-300 uppercase tracking-wider">Magic Links</p>
                  <p className="text-xs text-slate-500">Instant sharing with confetti.</p>
                </div>
              </div>
            </div>
          )}

          <div className={`${isSharedView ? 'max-w-2xl mx-auto w-full' : 'lg:col-span-7'} space-y-8`}>
            {!isSharedView && (
               <div className="flex items-center justify-between mb-4">
                  <div className="flex items-center gap-3">
                    <div className="w-1.5 h-6 bg-fuchsia-500 rounded-full" />
                    <h3 className="text-xl font-bold">Live Preview</h3>
                  </div>
               </div>
            )}

            <WishCard wish={wish} isLoading={isLoading} isSharedView={isSharedView} />

            {wish && !isLoading && (
              <div className="flex flex-wrap gap-4 animate-in fade-in slide-in-from-bottom-6 duration-1000">
                <button 
                  onClick={handleShare}
                  className="flex-[2] min-w-[200px] py-4 px-6 rounded-2xl bg-indigo-600 hover:bg-indigo-500 text-white font-bold flex items-center justify-center gap-3 transition-all shadow-xl shadow-indigo-600/20 active:scale-95 group"
                >
                  <Share2 className="w-5 h-5 group-hover:rotate-12 transition-transform" />
                  Share Magic Link
                </button>
                <button 
                  onClick={() => copyToClipboard(getShareUrl())}
                  className={`flex-1 min-w-[150px] py-4 px-6 rounded-2xl font-bold flex items-center justify-center gap-3 transition-all shadow-xl active:scale-95 border border-white/10 ${
                    isCopied 
                    ? 'bg-emerald-600 text-white border-emerald-500' 
                    : 'bg-slate-800/80 hover:bg-slate-700 text-slate-200'
                  }`}
                >
                  {isCopied ? (
                    <>
                      <Check className="w-5 h-5" />
                      Copied!
                    </>
                  ) : (
                    <>
                      <Link className="w-5 h-5" />
                      Copy Link
                    </>
                  )}
                </button>
              </div>
            )}
          </div>
        </div>
      </main>

      <footer className="mt-auto py-12 border-t border-white/5 bg-slate-900/40">
        <div className="max-w-7xl mx-auto px-6 flex flex-col md:flex-row items-center justify-between gap-6">
          <p className="text-slate-500 text-sm font-medium">
            Powered by <span className="text-slate-300">Gemini 3 Flash</span> & <span className="text-slate-300">Framer Motion</span>
          </p>
