import React, { useState, useEffect, useCallback } from 'react';
import WishForm from './components/WishForm';
import WishCard from './components/WishCard';
import { WishData, GeneratedWish, Occasion } from './types';
import { generateWish } from './services/geminiService';
import { Sparkles, Share2, Github, Plus, Volume2, Music, Link, Check } from 'lucide-react';
import confetti from 'canvas-confetti';
import { OCCASION_THEMES } from './lib/themes';

const App: React.FC = () => {
  const [wish, setWish] = useState<GeneratedWish | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isSharedView, setIsSharedView] = useState(false);
  const [isCopied, setIsCopied] = useState(false);

  // Reusable celebration effect with occasion-specific emojis
  const triggerConfetti = useCallback((occasion?: Occasion) => {
    const duration = 8 * 1000; // Increased from 4s to 8s
    const animationEnd = Date.now() + duration;

    // Get relevant emojis based on occasion or default
    const icons = occasion ? OCCASION_THEMES[occasion].bgIcons : ['✨', '🎉', '🎊', '⭐'];

    // Create shapes from emojis
    const shapes = icons.map(icon => confetti.shapeFromText({ text: icon, scalar: 3 }));

    const randomInRange = (min: number, max: number) => Math.random() * (max - min) + min;

    const interval: any = setInterval(function() {
      const timeLeft = animationEnd - Date.now();

      if (timeLeft <= 0) {
        return clearInterval(interval);
      }

      // Increased base particle count from 25 to 50
      const particleCount = 50 * (timeLeft / duration);

      // Left side burst
      confetti({
        particleCount,
        angle: 60,
        spread: 65,
        origin: { x: 0, y: 0.8 },
        shapes,
        scalar: 2.2,
        zIndex: 100,
      });

      // Right side burst
      confetti({
        particleCount,
        angle: 120,
        spread: 65,
        origin: { x: 1, y: 0.8 },
        shapes,
        scalar: 2.2,
        zIndex: 100,
      });

      // Increased random center drops frequency
      if (Math.random() > 0.6) {
        confetti({
          particleCount: 10,
          origin: { x: randomInRange(0.1, 0.9), y: randomInRange(0, 0.4) },
          shapes,
          gravity: 0.7,
          scalar: 1.8,
          zIndex: 100,
        });
      }
    }, 400);
  }, []);

  // Robust Unicode-safe Base64 Encoding
  const encodeData = (data: any) => {
    try {
      const json = JSON.stringify(data);
      const bytes = new TextEncoder().encode(json);
      let binary = "";
      const len = bytes.byteLength;
      for (let i = 0; i < len; i++) {
        binary += String.fromCharCode(bytes[i]);
      }
      return btoa(binary);
    } catch (e) {
      console.error("Encoding error:", e);
      return "";
    }
  };

  // Robust Unicode-safe Base64 Decoding
  const decodeData = (str: string) => {
    try {
      const binary = atob(str);
      const bytes = new Uint8Array(binary.length);
      for (let i = 0; i < binary.length; i++) {
        bytes[i] = binary.charCodeAt(i);
      }
      const json = new TextDecoder().decode(bytes);
      return JSON.parse(json);
    } catch (e) {
      console.error("Decoding error:", e);
      return null;
    }
  };

  // Handle Shared Link on Mount and Hash Change
  useEffect(() => {
    const handleHash = () => {
      const hash = window.location.hash;
      if (hash && hash.startsWith('#wish=')) {
        const encodedData = hash.replace('#wish=', '');
        const decodedData = decodeData(encodedData);
        if (decodedData) {
          setWish(decodedData);
          setIsSharedView(true);
          // Small delay to ensure the DOM is ready for the confetti canvas
          setTimeout(() => triggerConfetti(decodedData.occasion), 600);
        }
      }
    };

    handleHash();
    window.addEventListener('hashchange', handleHash);
    return () => window.removeEventListener('hashchange', handleHash);
  }, [triggerConfetti]);

  const handleGenerate = async (data: WishData) => {
    setIsLoading(true);
    setError(null);
    setIsSharedView(false);
    try {
      if (data.manualMessage && data.manualMessage.trim()) {
        const manualWish: GeneratedWish = {
          message: data.manualMessage.trim(),
          mood: 'custom',
          colorTheme: 'from-slate-800 to-slate-900', // Default, will be overridden by theme.gradient in WishCard anyway
          recipientName: data.recipientName,
          occasion: data.occasion
        };
        setWish(manualWish);
        triggerConfetti(data.occasion);
      } else {
        const result = await generateWish(data);
        setWish(result);
        triggerConfetti(result.occasion);
      }
    } catch (err) {
      console.error(err);
      setError("Failed to brew your magic wish. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const copyToClipboard = (text: string) => {
    const onCopySuccess = () => {
      setIsCopied(true);
      setTimeout(() => setIsCopied(false), 2000);
    };

    if (navigator.clipboard && window.isSecureContext) {
      navigator.clipboard.writeText(text)
        .then(onCopySuccess)
        .catch((err) => {
          console.warn("Clipboard API failed, trying fallback:", err);
          fallbackCopyTextToClipboard(text, onCopySuccess);
        });
    } else {
      fallbackCopyTextToClipboard(text, onCopySuccess);
    }
  };

  const fallbackCopyTextToClipboard = (text: string, callback?: () => void) => {
    const textArea = document.createElement("textarea");
    textArea.value = text;
    textArea.style.position = "fixed";
    textArea.style.left = "-999999px";
    textArea.style.top = "-999999px";
    document.body.appendChild(textArea);
    textArea.focus();
    textArea.select();

    try {
      const successful = document.execCommand('copy');
      if (successful && callback) callback();
      else if (!successful) prompt("Could not auto-copy. Please copy this link manually:", text);
    } catch (err) {
      console.error("Fallback copy failed:", err);
      prompt("Could not auto-copy. Please copy this link manually:", text);
    }

    document.body.removeChild(textArea);
  };

  const getShareUrl = () => {
    if (!wish) return '';
    const encodedWish = encodeData(wish);
    const baseUrl = window.location.href.split('#')[0];
    return `${baseUrl}#wish=${encodedWish}`;
  };

  const handleShare = async () => {
    const shareUrl = getShareUrl();
    if (!shareUrl) return;

    if (navigator.share) {
      try {
        await navigator.share({
          title: `Magic Wish for ${wish?.recipientName}`,
          text: `I created a special AI wish card for you! ✨`,
          url: shareUrl,
        });
      } catch (err: any) {
        if (err.name !== 'AbortError') {
          copyToClipboard(shareUrl);
        }
      }
    } else {
      copyToClipboard(shareUrl);
    }
  };

  return (
    <div className="min-h-screen bg-[#0f172a] text-slate-100 flex flex-col font-sans">
      <nav className="border-b border-white/5 bg-slate-900/60 backdrop-blur-xl sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => {
            window.location.hash = '';
            window.location.reload();
          }}>
            <div className="bg-gradient-to-br from-indigo-500 to-violet-600 p-2.5 rounded-xl shadow-lg shadow-indigo-500/20">
              <Sparkles className="w-6 h-6 text-white" />
            </div>
            <span className="text-2xl font-bold tracking-tight bg-gradient-to-r from-white to-slate-400 bg-clip-text text-transparent">
              WishCraft
            </span>
          </div>
          <div className="flex items-center gap-4">
            {isSharedView && (
              <button 
                onClick={() => { window.location.hash = ''; window.location.reload(); }}
                className="flex items-center gap-2 px-4 py-2 rounded-xl bg-indigo-600 text-sm font-bold hover:bg-indigo-500 transition-all shadow-lg shadow-indigo-500/10"
              >
                <Plus className="w-4 h-4" />
                Create Mine
              </button>
            )}
            <a href="https://github.com" target="_blank" rel="noopener noreferrer" className="p-2.5 hover:bg-white/5 rounded-xl transition-all border border-white/5">
              <Github className="w-5 h-5 text-slate-400" />
            </a>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-6 w-full pt-12 pb-24">
        {!isSharedView && !wish && (
          <header className="text-center max-w-3xl mx-auto mb-16 space-y-6">
            <h1 className="text-5xl md:text-7xl font-extrabold tracking-tight leading-tight">
              Personalized Wishes, <span className="bg-gradient-to-r from-indigo-400 to-fuchsia-400 bg-clip-text text-transparent">Perfected.</span>
            </h1>
            <p className="text-slate-400 text-lg md:text-xl font-medium leading-relaxed">
              Create cinematic, 3D animated cards with manual input or AI. 
              Share magic links with music, motion, and celebration.
            </p>
          </header>
        )}

        {isSharedView && (
           <div className="text-center mb-8 flex flex-col items-center gap-2 animate-bounce">
              <div className="p-3 bg-indigo-500/20 rounded-full text-indigo-400">
                <Volume2 className="w-6 h-6" />
              </div>
              <p className="text-indigo-400 font-bold uppercase tracking-[0.2em] text-xs">Sound On • Magic Inside</p>
           </div>
        )}

        <div className={`grid grid-cols-1 ${isSharedView ? 'lg:grid-cols-1 justify-center' : 'lg:grid-cols-12'} gap-12 items-start`}>
          {!isSharedView && (
            <div className="lg:col-span-5 space-y-8">
              <div className="bg-slate-800/30 border border-white/5 p-8 rounded-3xl backdrop-blur-md shadow-2xl">
                <div className="flex items-center gap-3 mb-8">
                  <div className="w-1.5 h-6 bg-indigo-500 rounded-full" />
                  <h3 className="text-xl font-bold">Craft Your Card</h3>
                </div>
                <WishForm onSubmit={handleGenerate} isLoading={isLoading} />
              </div>

              {error && (
                <div className="p-5 bg-rose-500/10 border border-rose-500/20 text-rose-400 rounded-2xl text-sm font-medium">
                  {error}
                </div>
              )}

              <div className="grid grid-cols-2 gap-4">
                <div className="p-6 rounded-3xl bg-white/5 border border-white/5 flex flex-col gap-3">
                  <Music className="w-6 h-6 text-indigo-400" />
                  <p className="text-xs font-bold text-slate-300 uppercase tracking-wider">Themed Audio</p>
                  <p className="text-xs text-slate-500">Fixed curated sounds for every occasion.</p>
                </div>
                <div className="p-6 rounded-3xl bg-white/5 border border-white/5 flex flex-col gap-3">
                  <Share2 className="w-6 h-6 text-fuchsia-400" />
                  <p className="text-xs font-bold text-slate-300 uppercase tracking-wider">Magic Links</p>
                  <p className="text-xs text-slate-500">Instant sharing with confetti.</p>
                </div>
              </div>
            </div>
          )}

          <div className={`${isSharedView ? 'max-w-2xl mx-auto w-full' : 'lg:col-span-7'} space-y-8`}>
            {!isSharedView && (
               <div className="flex items-center justify-between mb-4">
                  <div className="flex items-center gap-3">
                    <div className="w-1.5 h-6 bg-fuchsia-500 rounded-full" />
                    <h3 className="text-xl font-bold">Live Preview</h3>
                  </div>
               </div>
            )}

            <WishCard wish={wish} isLoading={isLoading} isSharedView={isSharedView} />

            {wish && !isLoading && (
              <div className="flex flex-wrap gap-4 animate-in fade-in slide-in-from-bottom-6 duration-1000">
                <button 
                  onClick={handleShare}
                  className="flex-[2] min-w-[200px] py-4 px-6 rounded-2xl bg-indigo-600 hover:bg-indigo-500 text-white font-bold flex items-center justify-center gap-3 transition-all shadow-xl shadow-indigo-600/20 active:scale-95 group"
                >
                  <Share2 className="w-5 h-5 group-hover:rotate-12 transition-transform" />
                  Share Magic Link
                </button>
                <button 
                  onClick={() => copyToClipboard(getShareUrl())}
                  className={`flex-1 min-w-[150px] py-4 px-6 rounded-2xl font-bold flex items-center justify-center gap-3 transition-all shadow-xl active:scale-95 border border-white/10 ${
                    isCopied 
                    ? 'bg-emerald-600 text-white border-emerald-500' 
                    : 'bg-slate-800/80 hover:bg-slate-700 text-slate-200'
                  }`}
                >
                  {isCopied ? (
                    <>
                      <Check className="w-5 h-5" />
                      Copied!
                    </>
                  ) : (
                    <>
                      <Link className="w-5 h-5" />
                      Copy Link
                    </>
                  )}
                </button>
              </div>
            )}
          </div>
        </div>
      </main>

      <footer className="mt-auto py-12 border-t border-white/5 bg-slate-900/40">
        <div className="max-w-7xl mx-auto px-6 flex flex-col md:flex-row items-center justify-between gap-6">
          <p className="text-slate-500 text-sm font-medium">
            Powered by <span className="text-slate-300">Gemini 3 Flash</span> & <span className="text-slate-300">Framer Motion</span>
          </p>
          <div className="flex items-center gap-8">
            <a href="#" className="text-slate-500 hover:text-white transition-colors text-xs font-bold uppercase tracking-widest">Privacy</a>
            <a href="#" className="text-slate-500 hover:text-white transition-colors text-xs font-bold uppercase tracking-widest">Feedback</a>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useEffect, useState, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { GeneratedWish } from '../types';
import { OCCASION_THEMES } from '../lib/themes';
import { Sparkles, Gift, Music, Download, VolumeX } from 'lucide-react';
import * as htmlToImage from 'html-to-image';
import gifshot from 'gifshot';

interface WishCardProps {
  wish: GeneratedWish | null;
  isLoading: boolean;
  isSharedView?: boolean;
}

const Floating3DIcon: React.FC<{ icon: string; delay: number }> = ({ icon, delay }) => {
  const [randoms] = useState(() => ({
    x: Math.random() * 100,
    y: Math.random() * 100,
    zStart: Math.random() * 200 - 100,
    zEnd: Math.random() * 300 - 50,
    rotateX: Math.random() * 360,
    rotateY: Math.random() * 360,
    rotateZ: Math.random() * 360,
    duration: 12 + Math.random() * 15,
    scale: 0.4 + Math.random() * 1.2,
    opacity: 0.3 + Math.random() * 0.5
  }));

  return (
    <motion.div
      initial={{ opacity: 0, z: randoms.zStart, rotateX: randoms.rotateX }}
      animate={{ 
        opacity: [0, randoms.opacity, randoms.opacity, 0],
        x: [`${randoms.x}%`, `${(randoms.x + 15) % 100}%`],
        y: [`${randoms.y}%`, `${(randoms.y - 20) % 100}%`],
        rotateX: [randoms.rotateX, randoms.rotateX + 720],
        rotateY: [randoms.rotateY, randoms.rotateY + 360],
        rotateZ: [randoms.rotateZ, randoms.rotateZ + 180],
        scale: [randoms.scale, randoms.scale * 1.4, randoms.scale],
        z: [randoms.zStart, randoms.zEnd]
      }}
      transition={{ 
        duration: randoms.duration, 
        repeat: Infinity, 
        delay,
        ease: "linear"
      }}
      className="absolute text-4xl pointer-events-none select-none drop-shadow-2xl filter blur-[0.5px]"
      style={{ 
        left: `${randoms.x}%`, 
        top: `${randoms.y}%`, 
        transformStyle: 'preserve-3d',
        willChange: 'transform, opacity'
      }}
    >
      {icon}
    </motion.div>
  );
};

const WishCard: React.FC<WishCardProps> = ({ wish, isLoading, isSharedView }) => {
  const [displayedMessage, setDisplayedMessage] = useState('');
  const [isGifExporting, setIsGifExporting] = useState(false);
  const [exportProgress, setExportProgress] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [audioBlocked, setAudioBlocked] = useState(false);
  const [audioError, setAudioError] = useState(false);
  const cardRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    if (wish?.message) {
      setDisplayedMessage('');
      let i = 0;
      const interval = setInterval(() => {
        setDisplayedMessage(wish.message.slice(0, i));
        i++;
        if (i > wish.message.length) clearInterval(interval);
      }, 50);

      const theme = OCCASION_THEMES[wish.occasion];
      if (theme?.audioUrl) {
        setAudioError(false);
        const audio = new Audio();

        audio.onplay = () => {
          setIsPlaying(true);
          setAudioBlocked(false);
        };
        audio.onpause = () => setIsPlaying(false);
        audio.onended = () => setIsPlaying(false);
        audio.onerror = () => {
          console.error("Failed to load audio source:", theme.audioUrl);
          setAudioError(true);
          setIsPlaying(false);
        };

        audio.src = theme.audioUrl;
        audio.loop = false;
        audio.volume = 0.5;

        audioRef.current = audio;

        // Autoplay attempt with a slight delay to ensure user interaction readiness
        const playPromise = audio.play();
        if (playPromise !== undefined) {
          playPromise.catch(() => {
            setAudioBlocked(true);
            setIsPlaying(false);
          });
        }
      }

      return () => {
        clearInterval(interval);
        if (audioRef.current) {
          audioRef.current.pause();
          audioRef.current.src = ""; // Stop the browser from loading the broken source
          audioRef.current = null;
        }
      };
    }
  }, [wish?.message, wish?.occasion]);

  const toggleAudio = () => {
    if (!audioRef.current || audioError) return;
    if (audioRef.current.paused) {
      if (audioRef.current.ended) {
        audioRef.current.currentTime = 0;
      }
      audioRef.current.play().then(() => {
        setAudioBlocked(false);
        setAudioError(false);
      }).catch(err => {
        console.warn("Playback failed:", err);
        setAudioBlocked(true);
      });
    } else {
      audioRef.current.pause();
    }
  };

  const captureGif = async () => {
    if (!cardRef.current || !wish) return;
    setIsGifExporting(true);
    setExportProgress(0);

    const frames: string[] = [];
    const frameCount = 12; 

    try {
      const options = {
        quality: 0.95,
        filter: (node: HTMLElement) => {
          const exclusionClasses = ['gif-controls'];
          return !exclusionClasses.some(cls => node.classList?.contains(cls));
        },
        style: { transform: 'scale(1)', borderRadius: '24px' }
      };

      for (let i = 0; i < frameCount; i++) {
        const dataUrl = await htmlToImage.toPng(cardRef.current, options);
        frames.push(dataUrl);
        setExportProgress(Math.round(((i + 1) / frameCount) * 50));
        await new Promise(r => setTimeout(r, 150));
      }

      gifshot.createGIF({
        images: frames,
        gifWidth: 400,
        gifHeight: 500,
        interval: 0.15,
        numFrames: frameCount,
      }, (obj: any) => {
        if (!obj.error) {
          const link = document.createElement('a');
          link.download = `WishCraft-${wish.recipientName}-${wish.occasion}.gif`;
          link.href = obj.image;
          link.click();
        }
        setIsGifExporting(false);
        setExportProgress(100);
      });
    } catch (err) {
      console.error(err);
      setIsGifExporting(false);
    }
  };

  if (isLoading) {
    return (
      <div className="w-full aspect-[4/5] rounded-3xl bg-slate-800 flex flex-col items-center justify-center p-8 border border-slate-700 shadow-2xl">
        <div className="relative">
          <div className="w-20 h-20 border-4 border-indigo-500/20 border-t-indigo-500 rounded-full animate-spin" />
          <Sparkles className="absolute inset-0 m-auto w-8 h-8 text-indigo-400 animate-pulse" />
        </div>
        <p className="mt-6 text-slate-400 font-medium animate-pulse tracking-wide">Weaving AI Magic...</p>
      </div>
    );
  }

  if (!wish) {
    return (
      <div className="w-full aspect-[4/5] rounded-3xl border-2 border-dashed border-slate-700 bg-slate-900/20 flex flex-col items-center justify-center p-12 text-center group">
        <motion.div 
          animate={{ y: [0, -10, 0] }} 
          transition={{ duration: 3, repeat: Infinity }}
          className="w-24 h-24 rounded-full bg-slate-800 flex items-center justify-center mb-6 shadow-xl"
        >
          <Gift className="w-12 h-12 text-slate-500" />
        </motion.div>
        <h3 className="text-2xl font-bold text-slate-300 mb-2">The Canvas Awaits</h3>
        <p className="text-slate-500 max-w-xs">Fill in the details to create a 3D animated wish masterpiece.</p>
      </div>
    );
  }

  const theme = OCCASION_THEMES[wish.occasion];

  return (
    <div className="relative group perspective-1000">
      <AnimatePresence mode="wait">
        <motion.div
          ref={cardRef}
          key={wish.message}
          initial={{ opacity: 0, rotateY: -10, scale: 0.9 }}
          animate={{ opacity: 1, rotateY: 0, scale: 1 }}
          exit={{ opacity: 0, scale: 1.1 }}
          className="w-full aspect-[4/5] rounded-3xl overflow-hidden relative shadow-2xl border border-white/20 preserve-3d"
        >
          <div className={`absolute inset-0 bg-gradient-to-br ${theme.gradient} opacity-95`} />

          <div className="absolute inset-0 overflow-hidden preserve-3d pointer-events-none">
            {/* Doubled icon volume for richer atmosphere */}
            {[...theme.bgIcons, ...theme.bgIcons, ...theme.bgIcons, ...theme.bgIcons].map((icon, idx) => (
              <Floating3DIcon key={idx} icon={icon} delay={idx * 0.8} />
            ))}
            {/* Doubled sparkle count from 6 to 12 */}
            {Array.from({ length: 12 }).map((_, idx) => (
              <Floating3DIcon key={`sp-${idx}`} icon="✨" delay={idx * 1.5} />
            ))}
          </div>

          <div className="absolute inset-0 bg-white/5 backdrop-blur-[0.5px] border-inset border-white/10" />

          <div className="absolute inset-0 flex flex-col items-center justify-center p-10 text-center z-20">
            <motion.div
              initial={{ scale: 0 }}
              animate={{ scale: 1 }}
              transition={{ type: 'spring', damping: 12, delay: 0.2 }}
              className="mb-8 relative"
            >
              <div className="w-24 h-24 rounded-full bg-black/20 backdrop-blur-xl flex items-center justify-center border border-white/30 shadow-2xl">
                <span className="text-5xl drop-shadow-lg">{theme.bgIcons[0]}</span>
              </div>
              <motion.div 
                animate={{ rotate: 360 }} 
                transition={{ duration: 12, repeat: Infinity, ease: "linear" }}
                className="absolute -inset-3 border-2 border-dashed border-white/20 rounded-full" 
              />
              <motion.div 
                animate={{ rotate: -360 }} 
                transition={{ duration: 20, repeat: Infinity, ease: "linear" }}
                className="absolute -inset-6 border border-white/10 rounded-full" 
              />
            </motion.div>

            <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.4 }}>
              <p className="text-white/70 uppercase tracking-[0.3em] text-xs font-bold mb-3 drop-shadow-sm">Happy {wish.occasion}</p>
              <h2 className="text-5xl md:text-6xl font-serif text-white mb-8 drop-shadow-[0_10px_10px_rgba(0,0,0,0.5)] leading-tight italic">
                {wish.recipientName}
              </h2>
            </motion.div>

            <div className="min-h-[120px] flex items-center justify-center max-w-md">
              <p className="text-2xl md:text-3xl text-white font-medium leading-relaxed drop-shadow-md">
                {displayedMessage}
                <motion.span
                  animate={{ opacity: [1, 0] }}
                  transition={{ duration: 0.8, repeat: Infinity }}
                  className="inline-block w-1.5 h-8 bg-white ml-2 align-middle shadow-lg"
                />
              </p>
            </div>

            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 2 }} className="mt-12 flex flex-col items-center gap-4">
