import React, { useState, useEffect, useCallback } from 'react';
import WishForm from './components/WishForm';
import WishCard from './components/WishCard';
import { WishData, GeneratedWish, Occasion } from './types';
import { generateWish } from './services/geminiService';
import { Sparkles, Share2, Github, Plus, Volume2, Music, Link, Check, AlertCircle } from 'lucide-react';
import confetti from 'canvas-confetti';
import { OCCASION_THEMES } from './lib/themes';

const App: React.FC = () => {
  const [wish, setWish] = useState<GeneratedWish | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isSharedView, setIsSharedView] = useState(false);
  const [isCopied, setIsCopied] = useState(false);

  // Reusable celebration effect with occasion-specific emojis
  const triggerConfetti = useCallback((occasion?: Occasion) => {
    const duration = 8 * 1000;
    const animationEnd = Date.now() + duration;

    const icons = occasion ? OCCASION_THEMES[occasion].bgIcons : ['✨', '🎉', '🎊', '⭐'];
    const shapes = icons.map(icon => confetti.shapeFromText({ text: icon, scalar: 3 }));
    const randomInRange = (min: number, max: number) => Math.random() * (max - min) + min;

    const interval: any = setInterval(function() {
      const timeLeft = animationEnd - Date.now();
      if (timeLeft <= 0) return clearInterval(interval);

      const particleCount = 50 * (timeLeft / duration);

      confetti({
        particleCount,
        angle: 60,
        spread: 65,
        origin: { x: 0, y: 0.8 },
        shapes,
        scalar: 2.2,
        zIndex: 100,
      });

      confetti({
        particleCount,
        angle: 120,
        spread: 65,
        origin: { x: 1, y: 0.8 },
        shapes,
        scalar: 2.2,
        zIndex: 100,
      });

      if (Math.random() > 0.6) {
        confetti({
          particleCount: 10,
          origin: { x: randomInRange(0.1, 0.9), y: randomInRange(0, 0.4) },
          shapes,
          gravity: 0.7,
          scalar: 1.8,
          zIndex: 100,
        });
      }
    }, 400);
  }, []);

  // Robust URL-Safe Base64 Encoding
  const encodeData = (data: any) => {
    try {
      const json = JSON.stringify(data);
      // Use encodeURIComponent to handle Unicode, then standard btoa
      const base64 = btoa(encodeURIComponent(json));
      // Make it URL-safe: + -> -, / -> _, remove =
      return base64.replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
    } catch (e) {
      console.error("Encoding error:", e);
      return "";
    }
  };

  // Robust URL-Safe Base64 Decoding
  const decodeData = (str: string) => {
    try {
      // Revert URL-safe characters: - -> +, _ -> /
      let base64 = str.replace(/-/g, '+').replace(/_/g, '/');
      // Re-add padding if necessary
      while (base64.length % 4) base64 += '=';

      const decoded = decodeURIComponent(atob(base64));
      return JSON.parse(decoded);
    } catch (e) {
      console.error("Decoding error:", e);
      return null;
    }
  };

  // Handle Shared Link on Mount and Hash Change
  useEffect(() => {
    const handleHash = () => {
      const hash = window.location.hash;
      // We look for 'wish=' anywhere in the hash to be safe
      const match = hash.match(/wish=([^&]*)/);
      if (match && match[1]) {
        const encodedData = match[1];
        const decodedData = decodeData(encodedData);
        if (decodedData) {
          setWish(decodedData);
          setIsSharedView(true);
          setError(null);
          setTimeout(() => triggerConfetti(decodedData.occasion), 600);
        } else {
          setError("This magic link seems to be broken. Try creating a new one!");
        }
      }
    };

    handleHash();
    window.addEventListener('hashchange', handleHash);
    return () => window.removeEventListener('hashchange', handleHash);
  }, [triggerConfetti]);

  const handleGenerate = async (data: WishData) => {
    setIsLoading(true);
    setError(null);
    setIsSharedView(false);
    try {
      if (data.manualMessage && data.manualMessage.trim()) {
        const manualWish: GeneratedWish = {
          message: data.manualMessage.trim(),
          mood: 'custom',
          colorTheme: 'from-slate-800 to-slate-900',
          recipientName: data.recipientName,
          occasion: data.occasion
        };
        setWish(manualWish);
        triggerConfetti(data.occasion);
      } else {
        const result = await generateWish(data);
        setWish(result);
        triggerConfetti(result.occasion);
      }
    } catch (err) {
      console.error(err);
      setError("Failed to brew your magic wish. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const copyToClipboard = (text: string) => {
    const onCopySuccess = () => {
      setIsCopied(true);
      setTimeout(() => setIsCopied(false), 2000);
    };

    if (navigator.clipboard && window.isSecureContext) {
      navigator.clipboard.writeText(text)
        .then(onCopySuccess)
        .catch((err) => {
          console.warn("Clipboard API failed, trying fallback:", err);
          fallbackCopyTextToClipboard(text, onCopySuccess);
        });
    } else {
      fallbackCopyTextToClipboard(text, onCopySuccess);
    }
  };

  const fallbackCopyTextToClipboard = (text: string, callback?: () => void) => {
    const textArea = document.createElement("textarea");
    textArea.value = text;
    textArea.style.position = "fixed";
    textArea.style.left = "-999999px";
    textArea.style.top = "-999999px";
    document.body.appendChild(textArea);
    textArea.focus();
    textArea.select();

    try {
      const successful = document.execCommand('copy');
      if (successful && callback) callback();
      else if (!successful) prompt("Could not auto-copy. Please copy this link manually:", text);
    } catch (err) {
      console.error("Fallback copy failed:", err);
      prompt("Could not auto-copy. Please copy this link manually:", text);
    }

    document.body.removeChild(textArea);
  };

  const getShareUrl = () => {
    if (!wish) return '';
    const encodedWish = encodeData(wish);
    const baseUrl = window.location.origin + window.location.pathname;
    return `${baseUrl}#wish=${encodedWish}`;
  };

  const handleShare = async () => {
    const shareUrl = getShareUrl();
    if (!shareUrl) return;

    if (navigator.share) {
      try {
        await navigator.share({
          title: `Magic Wish for ${wish?.recipientName}`,
          text: `✨ I crafted a special magic card for you! Open it to see the animation.`,
          url: shareUrl,
        });
      } catch (err: any) {
        if (err.name !== 'AbortError') {
          copyToClipboard(shareUrl);
        }
      }
    } else {
      copyToClipboard(shareUrl);
    }
  };

  const resetApp = () => {
    window.location.hash = '';
    setWish(null);
    setIsSharedView(false);
    setError(null);
  };

  return (
    <div className="min-h-screen bg-[#0f172a] text-slate-100 flex flex-col font-sans">
      <nav className="border-b border-white/5 bg-slate-900/60 backdrop-blur-xl sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer" onClick={resetApp}>
            <div className="bg-gradient-to-br from-indigo-500 to-violet-600 p-2.5 rounded-xl shadow-lg shadow-indigo-500/20">
              <Sparkles className="w-6 h-6 text-white" />
            </div>
            <span className="text-2xl font-bold tracking-tight bg-gradient-to-r from-white to-slate-400 bg-clip-text text-transparent">
              WishCraft
            </span>
          </div>
          <div className="flex items-center gap-4">
            {isSharedView && (
