const WishCard: React.FC<WishCardProps> = ({ wish, isLoading, isSharedView }) => {
  const [displayedMessage, setDisplayedMessage] = useState('');
  const [isWriting, setIsWriting] = useState(false);
  const [isGifExporting, setIsGifExporting] = useState(false);
  const [exportProgress, setExportProgress] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [audioBlocked, setAudioBlocked] = useState(false);
  const [audioError, setAudioError] = useState(false);
  const cardRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    if (wish?.message) {
      setDisplayedMessage('');
      setIsWriting(true);

      let i = 0;
      const writeChar = () => {
        if (i < wish.message.length) {
          setDisplayedMessage(wish.message.slice(0, i + 1));
          i++;
          // Randomize timing for realism: 30ms to 90ms per char
          const nextDelay = 30 + Math.random() * 60;
          setTimeout(writeChar, nextDelay);
        } else {
          setIsWriting(false);
        }
      };

      const timeout = setTimeout(writeChar, 500); // Small initial pause

      const theme = OCCASION_THEMES[wish.occasion];
      if (theme?.audioUrl) {
        setAudioError(false);
        const audio = new Audio();

        audio.onplay = () => {
          setIsPlaying(true);
          setAudioBlocked(false);
        };
        audio.onpause = () => setIsPlaying(false);
        audio.onended = () => setIsPlaying(false);
        audio.onerror = () => {
          setAudioError(true);
          setIsPlaying(false);
        };

        audio.src = theme.audioUrl;
        audio.loop = false;
        audio.volume = 0.5;

        audioRef.current = audio;

        const playPromise = audio.play();
        if (playPromise !== undefined) {
          playPromise.catch(() => {
            setAudioBlocked(true);
            setIsPlaying(false);
          });
        }
      }

      return () => {
        clearTimeout(timeout);
        if (audioRef.current) {
          audioRef.current.pause();
          audioRef.current.src = ""; 
          audioRef.current = null;
        }
      };
    }
  }, [wish?.message, wish?.occasion]);

  const toggleAudio = () => {
    if (!audioRef.current || audioError) return;
    if (audioRef.current.paused) {
      if (audioRef.current.ended) {
        audioRef.current.currentTime = 0;
      }
      audioRef.current.play().then(() => {
        setAudioBlocked(false);
        setAudioError(false);
      }).catch(() => setAudioBlocked(true));
    } else {
      audioRef.current.pause();
    }
  };

  const captureGif = async () => {
    if (!cardRef.current || !wish) return;
    setIsGifExporting(true);
    setExportProgress(0);

    const frames: string[] = [];
    const frameCount = 12; 

    try {
      const options = {
        quality: 0.95,
        filter: (node: HTMLElement) => {
          const exclusionClasses = ['gif-controls'];
          return !exclusionClasses.some(cls => node.classList?.contains(cls));
        },
        style: { transform: 'scale(1)', borderRadius: '24px' }
      };

      for (let i = 0; i < frameCount; i++) {
        const dataUrl = await htmlToImage.toPng(cardRef.current, options);
        frames.push(dataUrl);
        setExportProgress(Math.round(((i + 1) / frameCount) * 50));
        await new Promise(r => setTimeout(r, 150));
      }

      gifshot.createGIF({
        images: frames,
        gifWidth: 400,
        gifHeight: 500,
        interval: 0.15,
        numFrames: frameCount,
      }, (obj: any) => {
        if (!obj.error) {
          const link = document.createElement('a');
          link.download = `WishCraft-${wish.recipientName}-${wish.occasion}.gif`;
          link.href = obj.image;
          link.click();
        }
        setIsGifExporting(false);
        setExportProgress(100);
      });
    } catch (err) {
      console.error(err);
      setIsGifExporting(false);
    }
  };

  if (isLoading) {
    return (
      <div className="w-full aspect-[4/5] rounded-3xl bg-slate-800 flex flex-col items-center justify-center p-8 border border-slate-700 shadow-2xl">
        <div className="relative">
