              className={`w-10 h-10 flex items-center justify-center rounded-xl transition-all ${audioError ? 'bg-rose-900/50 text-rose-500' : isPlaying ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20' : 'bg-slate-800 text-slate-300 hover:bg-slate-700'}`}
              title={audioError ? "Audio could not be loaded" : isPlaying ? "Pause Audio" : "Play Audio"}
