const WishCard: React.FC<WishCardProps> = ({ wish, isLoading, isSharedView, replayCount }) => {
  const [displayedMessage, setDisplayedMessage] = useState('');
  const [isWriting, setIsWriting] = useState(false);
  const [showPen, setShowPen] = useState(false);
  const [isGifExporting, setIsGifExporting] = useState(false);
  const [exportProgress, setExportProgress] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [audioBlocked, setAudioBlocked] = useState(false);
  const [audioError, setAudioError] = useState(false);
  const cardRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    if (wish?.message) {
      setDisplayedMessage('');
      setIsWriting(true);
      setShowPen(true);

      let i = 0;
      let timeoutId: any = null;

      const writeChar = () => {
        if (i < wish.message.length) {
          setDisplayedMessage(wish.message.slice(0, i + 1));
          i++;
          const nextDelay = 35 + Math.random() * 65;
          timeoutId = setTimeout(writeChar, nextDelay);
        } else {
          setIsWriting(false);
          // We keep showPen(true) so it can blink at the end
        }
      };

      const initialDelay = setTimeout(writeChar, 800);

      const theme = OCCASION_THEMES[wish.occasion];
      if (theme?.audioUrl) {
        if (audioRef.current) {
          audioRef.current.pause();
          audioRef.current.src = "";
          audioRef.current = null;
        }

        setAudioError(false);
        const audio = new Audio();

        audio.onplay = () => {
          setIsPlaying(true);
          setAudioBlocked(false);
        };
        audio.onpause = () => setIsPlaying(false);
        audio.onended = () => setIsPlaying(false);
        audio.onerror = () => {
          setAudioError(true);
          setIsPlaying(false);
        };

        audio.src = theme.audioUrl;
        audio.loop = false;
        audio.volume = 0.5;

        audioRef.current = audio;

        const playPromise = audio.play();
        if (playPromise !== undefined) {
          playPromise.catch(() => {
            setAudioBlocked(true);
            setIsPlaying(false);
          });
        }
      }

      return () => {
        clearTimeout(initialDelay);
        if (timeoutId) clearTimeout(timeoutId);
        if (audioRef.current) {
          audioRef.current.pause();
          audioRef.current.src = ""; 
          audioRef.current = null;
        }
      };
    }
  }, [wish?.message, wish?.occasion, replayCount]);

  const toggleAudio = () => {
    if (!audioRef.current || audioError) return;
    if (audioRef.current.paused) {
      if (audioRef.current.ended) {
        audioRef.current.currentTime = 0;
      }
      audioRef.current.play().then(() => {
        setAudioBlocked(false);
        setAudioError(false);
      }).catch(() => setAudioBlocked(true));
    } else {
      audioRef.current.pause();
    }
  };

  const captureGif = async () => {
    if (!cardRef.current || !wish) return;
    setIsGifExporting(true);
    setExportProgress(0);

    const frames: string[] = [];
    const frameCount = 12; 

    try {
      const options = {
        quality: 0.95,
        filter: (node: HTMLElement) => {
          const exclusionClasses = ['gif-controls'];
          return !exclusionClasses.some(cls => node.classList?.contains(cls));
        },
        style: { transform: 'scale(1)', borderRadius: '24px' }
      };

      for (let i = 0; i < frameCount; i++) {
        const dataUrl = await htmlToImage.toPng(cardRef.current, options);
        frames.push(dataUrl);
        setExportProgress(Math.round(((i + 1) / frameCount) * 50));
        await new Promise(r => setTimeout(r, 150));
      }

      gifshot.createGIF({
        images: frames,
        gifWidth: 400,
        gifHeight: 500,
        interval: 0.15,
        numFrames: frameCount,
      }, (obj: any) => {
        if (!obj.error) {
          const link = document.createElement('a');
          link.download = `WishCraft-${wish.recipientName}-${wish.occasion}.gif`;
          link.href = obj.image;
          link.click();
        }
        setIsGifExporting(false);
        setExportProgress(100);
      });
    } catch (err) {
      console.error(err);
      setIsGifExporting(false);
    }
  };

  if (isLoading) {
    return (
      <div className="w-full aspect-[4/5] rounded-3xl bg-slate-800 flex flex-col items-center justify-center p-8 border border-slate-700 shadow-2xl">
        <div className="relative">
          <div className="w-20 h-20 border-4 border-indigo-500/20 border-t-indigo-500 rounded-full animate-spin" />
          <Sparkles className="absolute inset-0 m-auto w-8 h-8 text-indigo-400 animate-pulse" />
        </div>
        <p className="mt-6 text-slate-400 font-medium animate-pulse tracking-wide">Weaving AI Magic...</p>
      </div>
    );
  }

  if (!wish) {
    return (
      <div className="w-full aspect-[4/5] rounded-3xl border-2 border-dashed border-slate-700 bg-slate-900/20 flex flex-col items-center justify-center p-12 text-center group">
        <motion.div 
          animate={{ y: [0, -10, 0] }} 
          transition={{ duration: 3, repeat: Infinity }}
          className="w-24 h-24 rounded-full bg-slate-800 flex items-center justify-center mb-6 shadow-xl"
        >
          <Gift className="w-12 h-12 text-slate-500" />
        </motion.div>
        <h3 className="text-2xl font-bold text-slate-300 mb-2">The Canvas Awaits</h3>
        <p className="text-slate-500 max-w-xs">Fill in the details to create a 3D animated wish masterpiece.</p>
      </div>
    );
  }

  const theme = OCCASION_THEMES[wish.occasion];

  return (
    <div className="relative group perspective-1000">
      <AnimatePresence mode="wait">
        <motion.div
          ref={cardRef}
          key={`${wish.message}-${replayCount}`}
          initial={{ opacity: 0, rotateY: -10, scale: 0.9 }}
          animate={{ opacity: 1, rotateY: 0, scale: 1 }}
          exit={{ opacity: 0, scale: 1.1 }}
          className="w-full aspect-[4/5] rounded-3xl overflow-hidden relative shadow-2xl border border-white/20 preserve-3d"
        >
          <div className={`absolute inset-0 bg-gradient-to-br ${theme.gradient} opacity-95`} />

          <div className="absolute inset-0 overflow-hidden preserve-3d pointer-events-none">
            {[...theme.bgIcons, ...theme.bgIcons, ...theme.bgIcons, ...theme.bgIcons].map((icon, idx) => (
              <Floating3DIcon key={idx} icon={icon} delay={idx * 0.8} />
            ))}
            {Array.from({ length: 12 }).map((_, idx) => (
              <Floating3DIcon key={`sp-${idx}`} icon="✨" delay={idx * 1.5} />
            ))}
          </div>

          <div className="absolute inset-0 bg-white/5 backdrop-blur-[0.5px] border-inset border-white/10" />

          <div className="absolute inset-0 flex flex-col items-center justify-center p-10 text-center z-20">
            <motion.div
              initial={{ scale: 0 }}
              animate={{ scale: 1 }}
              transition={{ type: 'spring', damping: 12, delay: 0.2 }}
              className="mb-8 relative"
            >
              <div className="w-24 h-24 rounded-full bg-black/20 backdrop-blur-xl flex items-center justify-center border border-white/30 shadow-2xl">
                <span className="text-5xl drop-shadow-lg">{theme.bgIcons[0]}</span>
              </div>
              <motion.div 
                animate={{ rotate: 360 }} 
                transition={{ duration: 12, repeat: Infinity, ease: "linear" }}
                className="absolute -inset-3 border-2 border-dashed border-white/20 rounded-full" 
              />
              <motion.div 
                animate={{ rotate: -360 }} 
                transition={{ duration: 20, repeat: Infinity, ease: "linear" }}
                className="absolute -inset-6 border border-white/10 rounded-full" 
              />
            </motion.div>

            <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.4 }}>
              <p className="text-white/70 uppercase tracking-[0.3em] text-xs font-bold mb-3 drop-shadow-sm">Happy {wish.occasion}</p>
              <h2 className="text-5xl md:text-6xl font-serif text-white mb-8 drop-shadow-[0_10px_10px_rgba(0,0,0,0.5)] leading-tight italic">
                {wish.recipientName}
              </h2>
            </motion.div>

            <div className="min-h-[140px] flex items-center justify-center max-w-md w-full">
              <p className="text-3xl md:text-4xl text-white font-medium leading-[1.4] drop-shadow-lg font-handwritten relative">
                {displayedMessage}
                <AnimatePresence>
                  {showPen && (
                    <WritingPen 
                      key="writing-pen" 
                      isWriting={isWriting} 
                      color={theme.penColor} 
                    />
                  )}
                </AnimatePresence>
              </p>
            </div>

            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 2 }} className="mt-12 flex flex-col items-center gap-4">
              <div className="h-px w-20 bg-gradient-to-r from-transparent via-white/40 to-transparent" />
              <p className="text-white/50 text-[10px] uppercase tracking-[0.4em] font-semibold drop-shadow-sm">Designed by WishCraft AI</p>
            </motion.div>
          </div>

          <div className="absolute top-6 left-6 w-12 h-12 border-t-2 border-l-2 border-white/20 rounded-tl-xl" />
          <div className="absolute bottom-6 right-6 w-12 h-12 border-b-2 border-r-2 border-white/20 rounded-br-xl" />
        </motion.div>
      </AnimatePresence>

      {!isLoading && wish && (
        <div className="gif-controls absolute -bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-3 bg-slate-900/80 backdrop-blur-xl border border-white/10 p-2 rounded-2xl shadow-2xl z-30">
          <button 
            onClick={captureGif}
            disabled={isGifExporting}
            className="px-4 py-2 rounded-xl bg-indigo-600 hover:bg-indigo-500 text-white text-xs font-bold flex items-center gap-2 transition-all disabled:opacity-50"
          >
            {isGifExporting ? (
              <><div className="w-3 h-3 border-2 border-white/30 border-t-white rounded-full animate-spin" />{exportProgress}%</>
            ) : (
              <><Download className="w-4 h-4" />Get GIF</>
            )}
          </button>
          <div className="w-px h-6 bg-white/10" />
          <div className="flex items-center gap-2">
            <button 
              onClick={toggleAudio}
              disabled={audioError}
              className={`w-10 h-10 flex items-center justify-center rounded-xl transition-all ${audioError ? 'bg-rose-900/50 text-rose-500' : isPlaying ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20' : 'bg-slate-800 text-slate-300 hover:bg-slate-700'}`}
              title={audioError ? "Audio could not be loaded" : isPlaying ? "Pause Audio" : "Play Audio"}
            >
              {audioError ? <VolumeX className="w-4 h-4" /> : <Music className={`w-4 h-4 ${isPlaying ? 'animate-pulse' : ''}`} />}
            </button>
            {audioBlocked && !audioError && (
              <button onClick={toggleAudio} className="px-3 py-2 bg-indigo-600 rounded-xl text-[10px] font-bold uppercase tracking-wider animate-pulse text-white whitespace-nowrap">
                Tap for Sound
              </button>
            )}
            {audioError && (
              <span className="text-[10px] text-rose-400 font-bold uppercase tracking-wider whitespace-nowrap px-2">
                Audio Unavailable
              </span>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

