}

// Memoized Pen Component to prevent expensive re-renders during text revelation
const WritingPen = React.memo(({ isWriting, color }: { isWriting: boolean; color: string }) => (
  <motion.div
    initial={{ opacity: 0, scale: 0.15, rotate: -15 }}
    animate={isWriting ? {
      opacity: 1, 
      scale: 0.22,
      rotate: [-12, -16, -12, -8, -12],
      x: [-1, 1, -1, 1, -1],
      y: [0, -1, 0, -1, 0],
    } : {
      opacity: [1, 0.2, 1],
      scale: 0.22,
      rotate: -12,
      x: 0,
      y: 0,
      transition: { 
