    </svg>
  </motion.div>
));

// Memoized Background Icons to prevent 30+ components from re-rendering on every typed character
const Floating3DIcon = React.memo(({ icon, delay }: { icon: string; delay: number }) => {
  const randoms = useMemo(() => ({
    x: Math.random() * 100,
    y: Math.random() * 100,
    zStart: Math.random() * 200 - 100,
    zEnd: Math.random() * 300 - 50,
    rotateX: Math.random() * 360,
    rotateY: Math.random() * 360,
    rotateZ: Math.random() * 360,
    duration: 15 + Math.random() * 15,
    scale: 0.5 + Math.random() * 1.0,
    opacity: 0.2 + Math.random() * 0.4
  }), []);

  return (
    <motion.div
      initial={{ opacity: 0, z: randoms.zStart, rotateX: randoms.rotateX }}
      animate={{ 
        opacity: [0, randoms.opacity, randoms.opacity, 0],
        x: [`${randoms.x}%`, `${(randoms.x + 10) % 100}%`],
        y: [`${randoms.y}%`, `${(randoms.y - 15) % 100}%`],
        rotateX: [randoms.rotateX, randoms.rotateX + 360],
        rotateY: [randoms.rotateY, randoms.rotateY + 180],
        rotateZ: [randoms.rotateZ, randoms.rotateZ + 90],
        scale: [randoms.scale, randoms.scale * 1.2, randoms.scale],
        z: [randoms.zStart, randoms.zEnd]
      }}
      transition={{ 
        duration: randoms.duration, 
        repeat: Infinity, 
        delay,
        ease: "linear"
      }}
      className="absolute text-4xl pointer-events-none select-none drop-shadow-xl filter blur-[0.3px]"
      style={{ 
        left: `${randoms.x}%`, 
        top: `${randoms.y}%`, 
        transformStyle: 'preserve-3d',
        willChange: 'transform, opacity'
      }}
    >
      {icon}
    </motion.div>
  );
});

const WishCard: React.FC<WishCardProps> = ({ wish, isLoading, isSharedView, replayCount }) => {
  const [displayedMessage, setDisplayedMessage] = useState('');
  const [isWriting, setIsWriting] = useState(false);
  const [showPen, setShowPen] = useState(false);
  const [isGifExporting, setIsGifExporting] = useState(false);
  const [exportProgress, setExportProgress] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [audioBlocked, setAudioBlocked] = useState(false);
  const [audioError, setAudioError] = useState(false);

  const cardRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const typingTimerRef = useRef<number | null>(null);
  const charIndexRef = useRef(0);

  useEffect(() => {
    if (wish?.message) {
      // Reset logic
      if (typingTimerRef.current) clearTimeout(typingTimerRef.current);
      setDisplayedMessage('');
      charIndexRef.current = 0;
      setIsWriting(true);
      setShowPen(true);

      const theme = OCCASION_THEMES[wish.occasion];

      const writeChar = () => {
        if (charIndexRef.current < wish.message.length) {
          charIndexRef.current += 1;
          setDisplayedMessage(wish.message.slice(0, charIndexRef.current));

          const nextDelay = 35 + Math.random() * 45; // Tighter range for smoother feel
          typingTimerRef.current = window.setTimeout(writeChar, nextDelay);
        } else {
          setIsWriting(false);
        }
      };

      typingTimerRef.current = window.setTimeout(writeChar, 800);

      // Audio Logic
      if (theme?.audioUrl) {
        if (audioRef.current) {
          audioRef.current.pause();
          audioRef.current.src = "";
          audioRef.current = null;
        }

        setAudioError(false);
        const audio = new Audio();
        audio.onplay = () => { setIsPlaying(true); setAudioBlocked(false); };
        audio.onpause = () => setIsPlaying(false);
        audio.onended = () => setIsPlaying(false);
        audio.onerror = () => { setAudioError(true); setIsPlaying(false); };
        audio.src = theme.audioUrl;
        audio.loop = false;
        audio.volume = 0.5;
        audioRef.current = audio;

        const playPromise = audio.play();
        if (playPromise !== undefined) {
          playPromise.catch(() => { setAudioBlocked(true); setIsPlaying(false); });
        }
      }

      return () => {
        if (typingTimerRef.current) clearTimeout(typingTimerRef.current);
        if (audioRef.current) {
          audioRef.current.pause();
          audioRef.current.src = ""; 
          audioRef.current = null;
        }
      };
    }
  }, [wish?.message, wish?.occasion, replayCount]);

  const backgroundIcons = useMemo(() => {
    if (!wish) return null;
    const theme = OCCASION_THEMES[wish.occasion];
    return (
      <div className="absolute inset-0 overflow-hidden preserve-3d pointer-events-none">
        {theme.bgIcons.map((icon, idx) => (
          <Floating3DIcon key={`theme-${idx}`} icon={icon} delay={idx * 1.2} />
        ))}
        {Array.from({ length: 8 }).map((_, idx) => (
          <Floating3DIcon key={`sparkle-${idx}`} icon="✨" delay={idx * 2} />
        ))}
      </div>
    );
  }, [wish?.occasion]);

  const toggleAudio = () => {
    if (!audioRef.current || audioError) return;
    if (audioRef.current.paused) {
      audioRef.current.play().then(() => {
        setAudioBlocked(false);
        setAudioError(false);
      }).catch(() => setAudioBlocked(true));
    } else {
      audioRef.current.pause();
    }
  };

  const captureGif = async () => {
    if (!cardRef.current || !wish) return;
    setIsGifExporting(true);
    setExportProgress(0);
    const frames: string[] = [];
    const frameCount = 10; 

    try {
      const options = {
        quality: 0.9,
        filter: (node: HTMLElement) => !node.classList?.contains('gif-controls'),
        style: { transform: 'scale(1)', borderRadius: '24px' }
      };

      for (let i = 0; i < frameCount; i++) {
        const dataUrl = await htmlToImage.toPng(cardRef.current, options);
        frames.push(dataUrl);
        setExportProgress(Math.round(((i + 1) / frameCount) * 50));
        await new Promise(r => setTimeout(r, 200));
      }

      gifshot.createGIF({
        images: frames,
        gifWidth: 400,
        gifHeight: 500,
        interval: 0.2,
        numFrames: frameCount,
      }, (obj: any) => {
        if (!obj.error) {
          const link = document.createElement('a');
          link.download = `WishCraft-${wish.recipientName}.gif`;
          link.href = obj.image;
          link.click();
        }
        setIsGifExporting(false);
      });
    } catch (err) {
      console.error(err);
      setIsGifExporting(false);
    }
  };

  if (isLoading) {
    return (
      <div className="w-full aspect-[4/5] rounded-3xl bg-slate-800 flex flex-col items-center justify-center p-8 border border-slate-700 shadow-2xl">
        <div className="relative">
          <div className="w-20 h-20 border-4 border-indigo-500/20 border-t-indigo-500 rounded-full animate-spin" />
          <Sparkles className="absolute inset-0 m-auto w-8 h-8 text-indigo-400 animate-pulse" />
        </div>
        <p className="mt-6 text-slate-400 font-medium animate-pulse tracking-wide uppercase text-xs">Magic in Progress...</p>
      </div>
    );
  }

  if (!wish) {
    return (
      <div className="w-full aspect-[4/5] rounded-3xl border-2 border-dashed border-slate-700 bg-slate-900/20 flex flex-col items-center justify-center p-12 text-center group">
        <motion.div 
          animate={{ y: [0, -10, 0] }} 
          transition={{ duration: 3, repeat: Infinity }}
          className="w-24 h-24 rounded-full bg-slate-800 flex items-center justify-center mb-6 shadow-xl"
        >
          <Gift className="w-12 h-12 text-slate-500" />
        </motion.div>
        <h3 className="text-2xl font-bold text-slate-300 mb-2">Ready to Create?</h3>
        <p className="text-slate-500 max-w-xs text-sm">Fill in the form to generate your custom animated masterpiece.</p>
      </div>
    );
  }

  const theme = OCCASION_THEMES[wish.occasion];

  return (
    <div className="relative group perspective-1000">
      <AnimatePresence mode="wait">
        <motion.div
          ref={cardRef}
          key={`${wish.message}-${replayCount}`}
          initial={{ opacity: 0, rotateY: -5, scale: 0.98 }}
          animate={{ opacity: 1, rotateY: 0, scale: 1 }}
          exit={{ opacity: 0, scale: 1.02 }}
          transition={{ duration: 0.8 }}
          className="w-full aspect-[4/5] rounded-3xl overflow-hidden relative shadow-2xl border border-white/20 preserve-3d bg-slate-900"
        >
          <div className={`absolute inset-0 bg-gradient-to-br ${theme.gradient} opacity-90`} />
          {backgroundIcons}
          <div className="absolute inset-0 bg-white/5 backdrop-blur-[0.5px]" />

          <div className="absolute inset-0 flex flex-col items-center justify-center p-10 text-center z-20">
            <motion.div
              initial={{ scale: 0, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              transition={{ type: 'spring', damping: 15, delay: 0.3 }}
              className="mb-8 relative"
            >
              <div className="w-24 h-24 rounded-full bg-black/30 backdrop-blur-xl flex items-center justify-center border border-white/30 shadow-2xl">
                <span className="text-5xl drop-shadow-lg">{theme.bgIcons[0]}</span>
              </div>
              <motion.div 
                animate={{ rotate: 360 }} 
                transition={{ duration: 15, repeat: Infinity, ease: "linear" }}
                className="absolute -inset-4 border-2 border-dashed border-white/10 rounded-full" 
              />
            </motion.div>

            <motion.div initial={{ opacity: 0, y: 15 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.5 }}>
              <p className="text-white/80 uppercase tracking-[0.4em] text-[10px] font-bold mb-3 drop-shadow-sm">Special {wish.occasion} Wish</p>
              <h2 className="text-5xl md:text-6xl font-serif text-white mb-8 drop-shadow-[0_8px_12px_rgba(0,0,0,0.4)] leading-tight italic">
                {wish.recipientName}
              </h2>
            </motion.div>

            <div className="min-h-[120px] flex items-center justify-center max-w-md w-full relative">
              <p className="text-3xl md:text-4xl text-white font-medium leading-[1.4] drop-shadow-lg font-handwritten relative inline-block">
                {displayedMessage}
                {showPen && (
                  <WritingPen 
                    isWriting={isWriting} 
                    color={theme.penColor} 
                  />
                )}
              </p>
            </div>

            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 1.5 }} className="mt-12 flex flex-col items-center gap-4 opacity-60">
              <div className="h-px w-16 bg-gradient-to-r from-transparent via-white to-transparent" />
              <p className="text-white text-[9px] uppercase tracking-[0.5em] font-bold">WishCraft AI</p>
            </motion.div>
          </div>

          <div className="absolute top-6 left-6 w-10 h-10 border-t-2 border-l-2 border-white/20 rounded-tl-lg" />
          <div className="absolute bottom-6 right-6 w-10 h-10 border-b-2 border-r-2 border-white/20 rounded-br-lg" />
        </motion.div>
      </AnimatePresence>

      {!isLoading && wish && (
        <div className="gif-controls absolute -bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-3 bg-slate-900/90 backdrop-blur-2xl border border-white/10 p-2 rounded-2xl shadow-2xl z-30">
          <button 
            onClick={captureGif}
            disabled={isGifExporting}
            className="px-4 py-2 rounded-xl bg-indigo-600 hover:bg-indigo-500 text-white text-xs font-bold flex items-center gap-2 transition-all disabled:opacity-50"
          >
            {isGifExporting ? (
              <><div className="w-3 h-3 border-2 border-white/30 border-t-white rounded-full animate-spin" />{exportProgress}%</>
            ) : (
              <><Download className="w-4 h-4" />Save GIF</>
            )}
          </button>
          <div className="w-px h-6 bg-white/10" />
          <div className="flex items-center gap-2">
            <button 
              onClick={toggleAudio}
              disabled={audioError}
              className={`w-10 h-10 flex items-center justify-center rounded-xl transition-all ${audioError ? 'bg-rose-900/50 text-rose-500' : isPlaying ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-300'}`}
