    <motion.div
      initial={{ opacity: 0, z: randoms.zStart, rotateX: randoms.rotateX }}
      animate={{ 
        opacity: [0, randoms.opacity, randoms.opacity, 0],
        x: [`${randoms.x}%`, `${(randoms.x + 10) % 100}%`],
