      </AnimatePresence>

      {!isLoading && wish && (
        <div className="gif-controls absolute -bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-3 bg-slate-900/90 backdrop-blur-2xl border border-white/10 p-2 rounded-2xl shadow-2xl z-30">
          <button 
            onClick={captureGif}
            disabled={isGifExporting}
            className="px-4 py-2 rounded-xl bg-indigo-600 hover:bg-indigo-500 text-white text-xs font-bold flex items-center gap-2 transition-all disabled:opacity-50"
          >
            {isGifExporting ? (
              <><div className="w-3 h-3 border-2 border-white/30 border-t-white rounded-full animate-spin" />{exportProgress}%</>
            ) : (
              <><Download className="w-4 h-4" />Save GIF</>
            )}
          </button>
          <div className="w-px h-6 bg-white/10" />
          <div className="flex items-center gap-2">
            <button 
              onClick={toggleAudio}
              disabled={audioError}
              className={`w-10 h-10 flex items-center justify-center rounded-xl transition-all ${audioError ? 'bg-rose-900/50 text-rose-500' : isPlaying ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-300'}`}
            >
              {audioError ? <VolumeX className="w-4 h-4" /> : <Music className={`w-4 h-4 ${isPlaying ? 'animate-pulse' : ''}`} />}
            </button>
            {audioBlocked && !audioError && (
              <button onClick={toggleAudio} className="px-3 py-2 bg-indigo-600 rounded-xl text-[10px] font-bold uppercase tracking-wider text-white whitespace-nowrap animate-pulse">
                Tap Sound
              </button>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default WishCard;

import React, { useEffect, useState, useRef, useMemo } from 'react';
import { motion, AnimatePresence, useMotionValue, useSpring, useTransform } from 'framer-motion';
import { GeneratedWish } from '../types';
import { OCCASION_THEMES } from '../lib/themes';
import { Sparkles, Gift, Music, Download, VolumeX, ShieldCheck } from 'lucide-react';
import * as htmlToImage from 'html-to-image';
import gifshot from 'gifshot';

interface WishCardProps {
  wish: GeneratedWish | null;
  isLoading: boolean;
  isSharedView?: boolean;
  replayCount?: number;
}

const Floating3DIcon = React.memo(({ icon, delay }: { icon: string; delay: number }) => {
  const randoms = useMemo(() => ({
    x: Math.random() * 100,
    y: Math.random() * 100,
    zStart: Math.random() * 20,
    zEnd: Math.random() * 60 + 20,
    rotateX: Math.random() * 360,
    rotateY: Math.random() * 360,
    rotateZ: Math.random() * 360,
    duration: 10 + Math.random() * 10,
    scale: 0.6 + Math.random() * 0.8,
    opacity: 0.3 + Math.random() * 0.4
  }), []);

  return (
    <motion.div
      initial={{ opacity: 0, z: randoms.zStart, rotateX: randoms.rotateX }}
      animate={{ 
        opacity: [0, randoms.opacity, randoms.opacity, 0],
        x: [`${randoms.x}%`, `${(randoms.x + 5) % 100}%`],
        y: [`${randoms.y}%`, `${(randoms.y - 10) % 100}%`],
        rotateX: [randoms.rotateX, randoms.rotateX + 360],
        rotateY: [randoms.rotateY, randoms.rotateY + 180],
        rotateZ: [randoms.rotateZ, randoms.rotateZ + 90],
        scale: [randoms.scale, randoms.scale * 1.1, randoms.scale],
        z: [randoms.zStart, randoms.zEnd]
      }}
      transition={{ 
        duration: randoms.duration, 
        repeat: Infinity, 
        delay,
        ease: "linear"
      }}
      className="absolute text-3xl pointer-events-none select-none drop-shadow-xl filter blur-[0.2px]"
      style={{ 
        left: `${randoms.x}%`, 
        top: `${randoms.y}%`, 
        transformStyle: 'preserve-3d',
        willChange: 'transform, opacity'
      }}
    >
      {icon}
    </motion.div>
  );
});

const WishCard: React.FC<WishCardProps> = ({ wish, isLoading, isSharedView, replayCount }) => {
  const [displayedMessage, setDisplayedMessage] = useState('');
  const [isWriting, setIsWriting] = useState(false);
  const [isGifExporting, setIsGifExporting] = useState(false);
  const [exportProgress, setExportProgress] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [audioBlocked, setAudioBlocked] = useState(false);
  const [audioError, setAudioError] = useState(false);

  const containerRef = useRef<HTMLDivElement>(null);
  const cardRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const typingTimerRef = useRef<number | null>(null);
  const charIndexRef = useRef(0);

  // 3D Motion Values
  const x = useMotionValue(0);
  const y = useMotionValue(0);

  const mouseXSpring = useSpring(x, { stiffness: 150, damping: 20 });
  const mouseYSpring = useSpring(y, { stiffness: 150, damping: 20 });

  const rotateX = useTransform(mouseYSpring, [-0.5, 0.5], ["15deg", "-15deg"]);
  const rotateY = useTransform(mouseXSpring, [-0.5, 0.5], ["-15deg", "15deg"]);

  // Dynamic Shine based on rotation
  const shineX = useTransform(mouseXSpring, [-0.5, 0.5], ["0%", "100%"]);
  const shineY = useTransform(mouseYSpring, [-0.5, 0.5], ["0%", "100%"]);

  useEffect(() => {
    if (wish?.message) {
      if (typingTimerRef.current) clearTimeout(typingTimerRef.current);
      setDisplayedMessage('');
      charIndexRef.current = 0;
      setIsWriting(true);

      const writeChar = () => {
        if (charIndexRef.current < wish.message.length) {
          charIndexRef.current += 1;
          setDisplayedMessage(wish.message.slice(0, charIndexRef.current));
          typingTimerRef.current = window.setTimeout(writeChar, 40 + Math.random() * 40);
        } else {
          setIsWriting(false);
        }
      };

      typingTimerRef.current = window.setTimeout(writeChar, 1000);

      const theme = OCCASION_THEMES[wish.occasion];
      if (theme?.audioUrl) {
        if (audioRef.current) { audioRef.current.pause(); audioRef.current = null; }
        setAudioError(false);
        const audio = new Audio(theme.audioUrl);
        audio.onplay = () => { setIsPlaying(true); setAudioBlocked(false); };
        audio.onpause = () => setIsPlaying(false);
        audio.onended = () => setIsPlaying(false);
        audio.onerror = () => { setAudioError(true); setIsPlaying(false); };
        audio.volume = 0.5;
        audioRef.current = audio;
        audio.play().catch(() => setAudioBlocked(true));
      }

      return () => {
        if (typingTimerRef.current) clearTimeout(typingTimerRef.current);
        if (audioRef.current) { audioRef.current.pause(); audioRef.current = null; }
      };
    }
  }, [wish?.message, wish?.occasion, replayCount]);

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const width = rect.width;
    const height = rect.height;
    const mouseX = e.clientX - rect.left;
    const mouseY = e.clientY - rect.top;

    // Normalize to -0.5 to 0.5 range
    x.set((mouseX / width) - 0.5);
    y.set((mouseY / height) - 0.5);
  };

  const handleMouseLeave = () => {
    x.set(0);
    y.set(0);
  };

  const backgroundIcons = useMemo(() => {
    if (!wish) return null;
    const theme = OCCASION_THEMES[wish.occasion];
    return (
      <div className="absolute inset-0 overflow-hidden preserve-3d pointer-events-none translate-z-[10px]">
        {theme.bgIcons.map((icon, idx) => (
          <Floating3DIcon key={`theme-${idx}`} icon={icon} delay={idx * 1.5} />
        ))}
        {Array.from({ length: 6 }).map((_, idx) => (
          <Floating3DIcon key={`sparkle-${idx}`} icon="✨" delay={idx * 2.2} />
        ))}
      </div>
    );
  }, [wish?.occasion]);

  const toggleAudio = () => {
    if (!audioRef.current || audioError) return;
    audioRef.current.paused ? audioRef.current.play().catch(() => setAudioBlocked(true)) : audioRef.current.pause();
  };

  const captureGif = async () => {
    if (!cardRef.current || !wish) return;
    setIsGifExporting(true);
    setExportProgress(0);
    const frames: string[] = [];
    const frameCount = 12; 

    try {
      // Capture a slight rotation loop
      for (let i = 0; i < frameCount; i++) {
        // Mock rotation for capture by temporarily overriding motion values or just static
        const dataUrl = await htmlToImage.toPng(cardRef.current, {
          quality: 0.9,
          filter: (node: HTMLElement) => !node.classList?.contains('gif-controls'),
        });
        frames.push(dataUrl);
        setExportProgress(Math.round(((i + 1) / frameCount) * 100));
        await new Promise(r => setTimeout(r, 100));
      }

      gifshot.createGIF({
        images: frames,
        gifWidth: 400,
        gifHeight: 500,
        interval: 0.1,
        numFrames: frameCount,
      }, (obj: any) => {
        if (!obj.error) {
          const link = document.createElement('a');
          link.download = `WishCraft-${wish.recipientName}.gif`;
          link.href = obj.image;
          link.click();
        }
        setIsGifExporting(false);
      });
    } catch (err) {
      console.error(err);
      setIsGifExporting(false);
    }
  };

  if (isLoading) {
    return (
      <div className="w-full aspect-[4/5] rounded-3xl bg-slate-800 flex flex-col items-center justify-center p-8 border border-slate-700 shadow-2xl">
        <div className="relative">
          <div className="w-20 h-20 border-4 border-indigo-500/20 border-t-indigo-500 rounded-full animate-spin" />
          <Sparkles className="absolute inset-0 m-auto w-8 h-8 text-indigo-400 animate-pulse" />
        </div>
        <p className="mt-6 text-slate-400 font-medium animate-pulse tracking-wide uppercase text-xs">Forging Digital Magic...</p>
      </div>
    );
  }

  if (!wish) {
    return (
      <div className="w-full aspect-[4/5] rounded-3xl border-2 border-dashed border-slate-700 bg-slate-900/20 flex flex-col items-center justify-center p-12 text-center group">
        <motion.div animate={{ y: [0, -10, 0] }} transition={{ duration: 3, repeat: Infinity }} className="w-24 h-24 rounded-full bg-slate-800 flex items-center justify-center mb-6 shadow-xl">
          <Gift className="w-12 h-12 text-slate-500" />
        </motion.div>
        <h3 className="text-2xl font-bold text-slate-300 mb-2">3D Collective Awaits</h3>
        <p className="text-slate-500 max-w-xs text-sm">Design your card to see it in immersive 3D space.</p>
      </div>
    );
  }

  const theme = OCCASION_THEMES[wish.occasion];
  const textShadow3D = `0 1px 0 rgba(0,0,0,0.2), 0 2px 0 rgba(0,0,0,0.15), 0 3px 0 rgba(0,0,0,0.1), 0 4px 0 rgba(0,0,0,0.1), 0 5px 10px rgba(0,0,0,0.4), 0 10px 20px rgba(0,0,0,0.3)`;

  return (
    <div 
      ref={containerRef}
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
      className="relative group w-full aspect-[4/5] cursor-grab active:cursor-grabbing perspective-1000 select-none"
    >
      <motion.div
        ref={cardRef}
        key={`${wish.message}-${replayCount}`}
        style={{ rotateX, rotateY, transformStyle: 'preserve-3d' }}
        className="w-full h-full relative preserve-3d transition-transform duration-100"
      >
        {/* THICKNESS EDGES (The "Sides") */}
        <div className="absolute inset-0 bg-slate-900/80 rounded-3xl preserve-3d pointer-events-none">
            {/* Top edge */}
            <div className="absolute top-0 left-0 right-0 h-[6px] bg-slate-800 origin-top transform -rotateX-90 translate-z-[3px] rounded-t-3xl" style={{ transform: 'rotateX(90deg) translateZ(3px)' }} />
            {/* Bottom edge */}
            <div className="absolute bottom-0 left-0 right-0 h-[6px] bg-slate-800 origin-bottom transform rotateX-90 translate-z-[3px] rounded-b-3xl" style={{ transform: 'rotateX(-90deg) translateZ(3px)' }} />
            {/* Left edge */}
            <div className="absolute left-0 top-0 bottom-0 w-[6px] bg-slate-800 origin-left transform -rotateY-90 translate-z-[3px] rounded-l-3xl" style={{ transform: 'rotateY(-90deg) translateZ(3px)' }} />
            {/* Right edge */}
            <div className="absolute right-0 top-0 bottom-0 w-[6px] bg-slate-800 origin-right transform rotateY-90 translate-z-[3px] rounded-r-3xl" style={{ transform: 'rotateY(90deg) translateZ(3px)' }} />
        </div>

        {/* FRONT FACE */}
        <div className="absolute inset-0 rounded-3xl overflow-hidden preserve-3d border border-white/20 translate-z-[3px] backface-hidden shadow-[0_50px_100px_-20px_rgba(0,0,0,0.5)]">
          <div className={`absolute inset-0 bg-gradient-to-br ${theme.gradient} opacity-95`} />
          {backgroundIcons}
          <div className="absolute inset-0 bg-white/5 backdrop-blur-[0.5px]" />

          {/* Holographic Shine Overlay */}
          <motion.div 
            className="absolute inset-0 opacity-20 pointer-events-none"
            style={{ 
              background: `radial-gradient(circle at ${shineX} ${shineY}, white 0%, transparent 60%)`
            }}
          />

          <div className="absolute inset-0 flex flex-col items-center justify-center p-10 text-center z-20 translate-z-[40px]">
            <motion.div
              initial={{ scale: 0, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              transition={{ type: 'spring', damping: 15, delay: 0.3 }}
              className="mb-8 relative"
            >
              <div className="w-24 h-24 rounded-full bg-black/40 backdrop-blur-2xl flex items-center justify-center border border-white/30 shadow-2xl">
                <span className="text-5xl drop-shadow-2xl">{theme.bgIcons[0]}</span>
              </div>
              <motion.div 
                animate={{ rotate: 360 }} 
                transition={{ duration: 20, repeat: Infinity, ease: "linear" }}
                className="absolute -inset-4 border-2 border-dashed border-white/20 rounded-full" 
              />
            </motion.div>

            <div className="translate-z-[20px]">
              <p className="text-white/80 uppercase tracking-[0.4em] text-[10px] font-bold mb-3 drop-shadow-sm">Rare Edition • {wish.occasion}</p>

              <motion.h2 
                animate={{ y: [0, -8, 0] }}
                transition={{ duration: 4, repeat: Infinity, ease: "easeInOut" }}
                className="text-5xl md:text-6xl font-serif text-white mb-10 leading-tight italic"
                style={{ textShadow: textShadow3D }}
              >
                {wish.recipientName}
              </motion.h2>
            </div>

            <div className="min-h-[120px] flex items-center justify-center max-w-md w-full relative translate-z-[30px]">
              <p className="text-3xl md:text-4xl text-white font-medium leading-[1.4] drop-shadow-2xl font-handwritten">
                {displayedMessage}
              </p>
            </div>

            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 1.5 }} className="mt-12 flex flex-col items-center gap-4 opacity-50 translate-z-[10px]">
              <div className="h-px w-20 bg-gradient-to-r from-transparent via-white to-transparent" />
              <p className="text-white text-[9px] uppercase tracking-[0.5em] font-black">WishCraft Authentic</p>
            </motion.div>
          </div>

          <div className="absolute top-6 left-6 w-10 h-10 border-t-2 border-l-2 border-white/20 rounded-tl-lg" />
          <div className="absolute bottom-6 right-6 w-10 h-10 border-b-2 border-r-2 border-white/20 rounded-br-lg" />
        </div>

        {/* BACK FACE */}
        <div className="absolute inset-0 rounded-3xl overflow-hidden bg-slate-900 border-2 border-slate-700/50 -translate-z-[3px] rotateY-180 backface-hidden flex flex-col items-center justify-center" style={{ transform: 'rotateY(180deg) translateZ(3px)' }}>
           <div className="absolute inset-0 opacity-10" style={{ backgroundImage: `radial-gradient(circle at 2px 2px, ${theme.primaryColor} 1px, transparent 0)`, backgroundSize: '24px 24px' }} />
           <div className="relative flex flex-col items-center gap-4">
              <div className="w-32 h-32 rounded-3xl bg-slate-800 border border-white/10 flex items-center justify-center rotate-45 shadow-2xl">
                 <Sparkles className="w-16 h-16 text-indigo-500 -rotate-45" />
              </div>
              <p className="text-xl font-bold tracking-widest text-slate-400 mt-8">WISHCRAFT</p>
              <div className="flex items-center gap-2 px-3 py-1 rounded-full bg-slate-800 border border-white/5">
                <ShieldCheck className="w-3 h-3 text-emerald-500" />
                <span className="text-[10px] font-bold text-slate-500 uppercase tracking-tighter">Verified AI Generation</span>
              </div>
           </div>
           <div className="absolute bottom-8 text-[10px] text-slate-600 font-bold tracking-[0.5em] uppercase">Digital Asset ID #WC-7729</div>
        </div>
      </motion.div>

      {/* Control Overlays (Outside of 3D rotation) */}
      {!isLoading && wish && (
        <div className="gif-controls absolute -bottom-8 left-1/2 -translate-x-1/2 flex items-center gap-3 bg-slate-900/95 backdrop-blur-2xl border border-white/10 p-2.5 rounded-2xl shadow-2xl z-50">
          <button 
            onClick={captureGif}
            disabled={isGifExporting}
            className="px-5 py-2.5 rounded-xl bg-indigo-600 hover:bg-indigo-500 text-white text-xs font-bold flex items-center gap-2 transition-all disabled:opacity-50"
          >
            {isGifExporting ? (
              <><div className="w-3 h-3 border-2 border-white/30 border-t-white rounded-full animate-spin" />{exportProgress}%</>
            ) : (
              <><Download className="w-4 h-4" />Export Card</>
            )}
          </button>
          <div className="w-px h-8 bg-white/10 mx-1" />
          <div className="flex items-center gap-2">
            <button 
              onClick={toggleAudio}
              disabled={audioError}
              className={`w-11 h-11 flex items-center justify-center rounded-xl transition-all ${audioError ? 'bg-rose-900/50 text-rose-500' : isPlaying ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20' : 'bg-slate-800 text-slate-300 hover:bg-slate-700'}`}
            >
              {audioError ? <VolumeX className="w-4 h-4" /> : <Music className={`w-4 h-4 ${isPlaying ? 'animate-pulse' : ''}`} />}
            </button>
            {audioBlocked && !audioError && (
              <button onClick={toggleAudio} className="px-4 py-2 bg-indigo-600 rounded-xl text-[10px] font-black uppercase tracking-widest text-white whitespace-nowrap animate-pulse shadow-lg shadow-indigo-500/30">
                Unlock Audio
              </button>
            )}
          </div>
        </div>
      )}

      {/* Interaction Hint */}
      {wish && !isLoading && (
        <div className="absolute -top-12 left-1/2 -translate-x-1/2 opacity-0 group-hover:opacity-100 transition-opacity duration-500 flex items-center gap-2 text-slate-500 pointer-events-none">
          <Sparkles className="w-4 h-4" />
          <span className="text-[10px] font-bold uppercase tracking-[0.2em]">Hover to Tilt • Explore Depth</span>
        </div>
      )}
    </div>
  );
};

export default WishCard;
